import React, { useState } from 'react';
import { PDFDocument } from '../types';

interface PDFManagerProps {
  onUpload: (doc: PDFDocument) => void;
  documents: PDFDocument[];
  onDelete: (id: string) => void;
}

const PDFManager: React.FC<PDFManagerProps> = ({ onUpload, documents, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    // Simulate extraction and chunking
    setTimeout(() => {
      const newDoc: PDFDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        content: `Simulated content extraction for ${file.name}. This document covers advanced academic topics...`,
        uploadDate: new Date(),
        summary: "A brief summary of the academic material uploaded."
      };
      onUpload(newDoc);
      setIsUploading(false);
    }, 2000);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 p-6">
      <div className="bg-slate-900 rounded-2xl border border-slate-800 p-8 text-center space-y-4">
        <div className="inline-flex p-4 bg-indigo-500/10 rounded-full">
          <svg className="w-8 h-8 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
          </svg>
        </div>
        <div>
          <h2 className="text-2xl font-bold">Knowledge Engine</h2>
          <p className="text-slate-400">Upload your PDFs, textbooks, or notes. We'll extract and structure the knowledge for your personal tutor.</p>
        </div>

        <label className="inline-block px-8 py-3 bg-indigo-600 hover:bg-indigo-500 rounded-xl font-semibold cursor-pointer transition-colors">
          {isUploading ? 'Analyzing Knowledge...' : 'Select PDF Files'}
          <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} disabled={isUploading} />
        </label>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {documents.map(doc => (
          <div key={doc.id} className="bg-slate-900 border border-slate-800 rounded-xl p-5 flex items-start justify-between">
            <div className="flex items-center space-x-4">
              <div className="p-3 bg-red-500/10 rounded-lg">
                <svg className="w-6 h-6 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <div>
                <h4 className="font-semibold text-slate-100">{doc.name}</h4>
                <p className="text-xs text-slate-500">Uploaded on {doc.uploadDate.toLocaleDateString()}</p>
              </div>
            </div>
            <button 
              onClick={() => onDelete(doc.id)}
              className="p-2 text-slate-500 hover:text-red-400 transition-colors"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PDFManager;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Avatar from './Avatar';
import { Message, PDFDocument } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decode, decodeAudioData, encode } from '../services/geminiService';
import { KHULA_SYSTEM_INSTRUCTION } from '../constants';

interface TutoringViewProps {
  documents: PDFDocument[];
}

const TutoringView: React.FC<TutoringViewProps> = ({ documents }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isLiveActive, setIsLiveActive] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputNodeRef = useRef<GainNode | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const chatScrollRef = useRef<HTMLDivElement>(null);
  const sessionPromiseRef = useRef<any>(null);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [messages]);

  const toggleLiveSession = async () => {
    if (isLiveActive) {
      // Logic to close session would go here
      setIsLiveActive(false);
      setIsListening(false);
      return;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    audioContextRef.current = outputAudioContext;
    outputNodeRef.current = outputAudioContext.createGain();
    outputNodeRef.current.connect(outputAudioContext.destination);

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          setIsLiveActive(true);
          setIsListening(true);
          const source = inputAudioContext.createMediaStreamSource(stream);
          const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const pcmBlob = createPcmBlob(inputData);
            sessionPromise.then((session) => {
              session.sendRealtimeInput({ media: pcmBlob });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(inputAudioContext.destination);
        },
        onmessage: async (message: LiveServerMessage) => {
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio) {
            setIsSpeaking(true);
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
            const source = outputAudioContext.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outputNodeRef.current!);
            source.addEventListener('ended', () => {
              sourcesRef.current.delete(source);
              if (sourcesRef.current.size === 0) setIsSpeaking(false);
            });
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            sourcesRef.current.add(source);
          }
          if (message.serverContent?.interrupted) {
            sourcesRef.current.forEach(s => s.stop());
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
            setIsSpeaking(false);
          }
        },
        onerror: (e) => console.error(e),
        onclose: () => setIsLiveActive(false)
      },
      config: {
        responseModalities: [Modality.AUDIO],
        systemInstruction: KHULA_SYSTEM_INSTRUCTION + ` Context from documents: ${documents.map(d => d.name).join(', ')}`,
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
      }
    });

    sessionPromiseRef.current = sessionPromise;
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!inputText.trim()) return;

    const userMsg: Message = { role: 'user', text: inputText, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsThinking(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })), { role: 'user', parts: [{ text: inputText }] }],
        config: {
          systemInstruction: KHULA_SYSTEM_INSTRUCTION + ` Document context: ${documents.map(d => d.content).join('\n')}`,
        }
      });

      const tutorMsg: Message = { 
        role: 'model', 
        text: response.text || "I apologize, I couldn't process that. Let's try again.", 
        timestamp: new Date() 
      };
      setMessages(prev => [...prev, tutorMsg]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsThinking(false);
    }
  };

  return (
    <div className="flex h-[calc(100vh-6rem)] gap-6 p-4">
      {/* Sidebar: Chat Interface */}
      <div className="w-1/3 flex flex-col glass-morphism rounded-2xl border border-slate-800">
        <div className="p-4 border-b border-slate-800 flex justify-between items-center">
          <h3 className="font-bold flex items-center space-x-2">
            <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
            <span>Academic Chat</span>
          </h3>
          <span className="text-xs text-slate-500">{documents.length} materials grounded</span>
        </div>

        <div ref={chatScrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 chat-scroll">
          {messages.length === 0 && (
            <div className="h-full flex items-center justify-center text-slate-500 text-center p-8">
              <p>Welcome! Start by typing a question about your uploaded materials or click the microphone to talk.</p>
            </div>
          )}
          {messages.map((m, idx) => (
            <div key={idx} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`
                max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed
                ${m.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700'}
              `}>
                {m.text}
              </div>
            </div>
          ))}
          {isThinking && (
            <div className="flex justify-start">
              <div className="bg-slate-800 p-3 rounded-2xl rounded-tl-none border border-slate-700">
                <div className="flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                  <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                  <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
                </div>
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSendMessage} className="p-4 border-t border-slate-800">
          <div className="relative">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Ask anything about your notes..."
              className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-indigo-500 transition-colors pr-24"
            />
            <div className="absolute right-2 top-1.5 flex space-x-1">
              <button 
                type="button"
                onClick={toggleLiveSession}
                className={`p-2 rounded-lg transition-colors ${isLiveActive ? 'bg-emerald-500/20 text-emerald-400' : 'text-slate-500 hover:text-slate-100'}`}
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              </button>
              <button 
                type="submit"
                className="p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-500 transition-colors"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
              </button>
            </div>
          </div>
        </form>
      </div>

      {/* Main Avatar Canvas */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-12">
        <div className="w-full max-w-xl">
           <Avatar isThinking={isThinking} isSpeaking={isSpeaking} isListening={isListening} />
        </div>

        <div className="flex space-x-4">
          <button className="px-6 py-3 bg-slate-900 border border-slate-800 rounded-xl hover:bg-slate-800 transition-all flex items-center space-x-2">
            <svg className="w-5 h-5 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            <span className="font-semibold">Guided Lesson</span>
          </button>
          <button className="px-6 py-3 bg-slate-900 border border-slate-800 rounded-xl hover:bg-slate-800 transition-all flex items-center space-x-2">
            <svg className="w-5 h-5 text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
            <span className="font-semibold">Context Check</span>
          </button>
        </div>

        <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 w-full max-w-3xl">
          <h4 className="text-sm font-bold text-slate-500 uppercase tracking-tighter mb-4">Syllabus Insights</h4>
          <div className="grid grid-cols-3 gap-4">
             {['Key Definitions', 'Weak Topics', 'Revision Plan'].map(label => (
               <div key={label} className="p-3 bg-slate-800/50 rounded-lg text-xs font-medium text-slate-400 border border-slate-700/50 hover:border-slate-500 cursor-pointer transition-all">
                 Generate {label}
               </div>
             ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default TutoringView;

import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
}

const ExamMode: React.FC<ExamModeProps> = ({ documents }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    if (selectedAnswer === questions[currentIdx].correctAnswer) {
      setScore(s => s + 1);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="h-[70vh] flex flex-col items-center justify-center text-center p-8 space-y-6">
        <div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center border border-slate-800">
          <svg className="w-12 h-12 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div>
          <h2 className="text-2xl font-bold">No Material Found</h2>
          <p className="text-slate-400">Upload textbooks or notes in the "Documents" section to generate your custom exam.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="h-[70vh] flex flex-col items-center justify-center space-y-6">
        <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-xl font-medium animate-pulse">Syllabus-Grounding in Progress...</p>
      </div>
    );
  }

  if (isCompleted) {
    return (
      <div className="max-w-2xl mx-auto py-12 text-center space-y-8">
        <div className="relative inline-block">
          <svg className="w-32 h-32 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </div>
        <div>
          <h2 className="text-4xl font-bold mb-2">Exam Completed</h2>
          <p className="text-slate-400">You scored {score} out of {questions.length}</p>
        </div>
        <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800">
          <h3 className="font-bold text-indigo-400 mb-4 uppercase tracking-widest text-sm">Performance Analysis</h3>
          <p className="text-sm text-slate-400 leading-relaxed">
            Your performance indicates a strong grasp of the foundational concepts, but review "Part 2" of your uploaded documents for better clarity on terminology.
          </p>
        </div>
        <button onClick={startExam} className="px-8 py-3 bg-indigo-600 rounded-xl font-bold hover:bg-indigo-500 transition-colors">Retake New Exam</button>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-3xl mx-auto py-12 space-y-8 px-4">
        <div className="flex justify-between items-center text-sm font-bold text-slate-500 uppercase tracking-widest">
          <span>Question {currentIdx + 1} of {questions.length}</span>
          <span className="text-indigo-400">Score: {score}</span>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-8 space-y-8 shadow-2xl">
          <h3 className="text-2xl font-semibold leading-snug">{q.question}</h3>

          <div className="space-y-3">
            {q.options.map((opt, i) => (
              <button 
                key={i}
                onClick={() => setSelectedAnswer(i)}
                className={`
                  w-full text-left p-4 rounded-xl border transition-all duration-200
                  ${selectedAnswer === i 
                    ? 'bg-indigo-600/20 border-indigo-500 text-white shadow-[0_0_15px_rgba(99,102,241,0.2)]' 
                    : 'bg-slate-800/30 border-slate-700 text-slate-400 hover:border-slate-500'}
                `}
              >
                <div className="flex items-center space-x-3">
                  <span className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${selectedAnswer === i ? 'bg-indigo-500 text-white' : 'bg-slate-700'}`}>
                    {String.fromCharCode(65 + i)}
                  </span>
                  <span>{opt}</span>
                </div>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-end">
          <button 
            disabled={selectedAnswer === null}
            onClick={handleNext}
            className={`px-10 py-4 rounded-xl font-bold transition-all ${selectedAnswer !== null ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}`}
          >
            {currentIdx === questions.length - 1 ? 'Finish Exam' : 'Next Question'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[70vh] flex flex-col items-center justify-center space-y-8">
      <div className="text-center max-w-lg space-y-4">
        <h2 className="text-4xl font-black bg-gradient-to-r from-indigo-400 to-purple-400 bg-clip-text text-transparent">Smart Exam Mode</h2>
        <p className="text-slate-400 leading-relaxed">Simulate a high-stakes exam environment. Our AI generates questions exclusively from your uploaded content to ensure syllabus alignment.</p>
      </div>
      <button 
        onClick={startExam}
        className="group relative px-12 py-5 bg-indigo-600 rounded-2xl font-bold text-lg overflow-hidden transition-all hover:scale-105 active:scale-95"
      >
        <div className="absolute inset-0 bg-gradient-to-r from-white/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
        Generate Exam Paper
      </button>
    </div>
  );
};

