                  {/* Decorative element */}
                  <div className="absolute -right-20 -bottom-20 w-96 h-96 bg-white/10 rounded-full blur-3xl"></div>
                  <div className="absolute right-20 top-0 w-64 h-64 bg-indigo-400/20 rounded-full blur-2xl"></div>
               </div>

               {/* Quick Action Cards */}
               <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  <div className="bg-slate-900 p-10 rounded-[2rem] border border-slate-800 hover:border-indigo-500/50 transition-all group cursor-pointer" onClick={() => setActiveView(AppView.DOCUMENTS)}>
                    <div className="w-14 h-14 bg-indigo-500/10 text-indigo-400 rounded-2xl flex items-center justify-center mb-8 group-hover:scale-110 transition-transform">
                      {UI_ICONS.Documents}
                    </div>
                    <h3 className="text-2xl font-black mb-3">Intelligence Hub</h3>
                    <p className="text-slate-400 text-sm leading-relaxed mb-6">Manage your PDF intelligence. Upload textbooks, lecture notes, or research papers.</p>
                    <div className="text-indigo-400 text-[10px] font-black uppercase tracking-[0.2em] group-hover:translate-x-2 transition-transform">Update Materials &rarr;</div>
                  </div>

                  <div 
