                    <h3 className="text-2xl font-black mb-3">Exam Readiness</h3>
                    <p className="text-slate-400 text-sm leading-relaxed mb-6">Simulate exam conditions with questions generated strictly from your own materials.</p>
                    <div className="text-purple-400 text-[10px] font-black uppercase tracking-[0.2em] group-hover:translate-x-2 transition-transform">
                      {documents.length > 0 ? 'Test Mastery \u2192' : 'Locked (Requires PDF) \u2192'}
