import React, { useState, useEffect, useRef } from 'react';
import Avatar from './Avatar';
import { Message, PDFDocument } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decode, decodeAudioData } from '../services/geminiService';
import { KHULA_SYSTEM_INSTRUCTION } from '../constants';

interface TutoringViewProps {
  documents: PDFDocument[];
}

const TutoringView: React.FC<TutoringViewProps> = ({ documents }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isThinking, setIsThinking] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isLiveActive, setIsLiveActive] = useState(false);
  const [showTranscript, setShowTranscript] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputNodeRef = useRef<GainNode | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const chatScrollRef = useRef<HTMLDivElement>(null);
  const sessionPromiseRef = useRef<any>(null);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Clean up session on unmount
  useEffect(() => {
    return () => {
      if (sessionPromiseRef.current) {
        sessionPromiseRef.current.then((session: any) => session.close());
      }
    };
  }, []);

  const startSession = async () => {
    if (isLiveActive) return;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    audioContextRef.current = outputAudioContext;
    outputNodeRef.current = outputAudioContext.createGain();
    outputNodeRef.current.connect(outputAudioContext.destination);

    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          setIsLiveActive(true);
          setIsListening(true);
          const source = inputAudioContext.createMediaStreamSource(stream);
          const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const pcmBlob = createPcmBlob(inputData);
            sessionPromise.then((session) => {
              session.sendRealtimeInput({ media: pcmBlob });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(inputAudioContext.destination);

          // Initial prompt to trigger the self-introduction and summary
          sessionPromise.then((session) => {
            session.sendRealtimeInput({ text: "Please introduce yourself and summarize my materials to begin our session." });
          });
        },
        onmessage: async (message: LiveServerMessage) => {
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          const textResponse = message.serverContent?.modelTurn?.parts[0]?.text;

          if (textResponse) {
             setMessages(prev => [...prev, { role: 'model', text: textResponse, timestamp: new Date() }]);
          }

          if (base64Audio) {
            setIsSpeaking(true);
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
            const source = outputAudioContext.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outputNodeRef.current!);
            source.addEventListener('ended', () => {
              sourcesRef.current.delete(source);
              if (sourcesRef.current.size === 0) setIsSpeaking(false);
            });
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            sourcesRef.current.add(source);
          }

          if (message.serverContent?.interrupted) {
            for (const source of sourcesRef.current.values()) {
              source.stop();
            }
            sourcesRef.current.clear();
            nextStartTimeRef.current = 0;
            setIsSpeaking(false);
          }
        },
        onerror: (e) => console.error(e),
        onclose: () => {
          setIsLiveActive(false);
          setIsListening(false);
        }
      },
      config: {
        responseModalities: [Modality.AUDIO],
        systemInstruction: KHULA_SYSTEM_INSTRUCTION + ` \n\nCONTENT GROUNDING: Use this extracted knowledge: ${documents.map(d => d.content).join('\n')}`,
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
      }
    });

    sessionPromiseRef.current = sessionPromise;
  };

  const endSession = () => {
    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then((session: any) => session.close());
      setIsLiveActive(false);
      setIsListening(false);
      setIsSpeaking(false);
      setMessages([]);
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden relative">
      {/* Background Ambience */}
      <div className={`absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] transition-all duration-1000 ${isLiveActive ? 'from-indigo-600/10 via-slate-950 to-slate-950' : 'from-slate-900/40 via-slate-950 to-slate-950'}`}></div>

      {/* Main Conversation Stage */}
      <div className="flex-1 flex flex-col items-center justify-center z-10 p-12">
        {!isLiveActive ? (
          <div className="text-center space-y-8 max-w-2xl animate-in zoom-in-95 duration-700">
            <div className="inline-flex p-4 bg-indigo-500/10 rounded-3xl border border-indigo-500/20 mb-4">
              <svg className="w-12 h-12 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <h2 className="text-5xl font-black bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">Enter the Conversation Room</h2>
            <p className="text-slate-400 text-lg leading-relaxed">
              Khula is ready to guide you through your {documents.length} materials. This is a voice-first immersive session focused on high-recall learning.
            </p>
            <button 
              onClick={startSession}
              className="px-12 py-5 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-black text-sm uppercase tracking-[0.2em] shadow-2xl shadow-indigo-600/30 transition-all hover:scale-105 active:scale-95"
            >
              Initialize Voice Session
            </button>
          </div>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center relative">
            {/* Immersive Avatar focus */}
            <div className="w-full max-w-xl mb-12 transform scale-110 transition-transform duration-1000">
               <Avatar isThinking={isThinking} isSpeaking={isSpeaking} isListening={isListening} />
            </div>

            {/* Conversation Controls */}
            <div className="flex items-center space-x-8 mt-12">
              <button 
                onClick={() => setShowTranscript(!showTranscript)}
                className={`p-5 rounded-2xl border transition-all ${showTranscript ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
                title="Toggle Transcript"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              </button>

              <div className={`p-8 rounded-full border-4 transition-all duration-500 ${isSpeaking ? 'border-indigo-500 bg-indigo-500/10' : isListening ? 'border-emerald-500 bg-emerald-500/10' : 'border-slate-800 bg-slate-900'}`}>
                 <div className="w-12 h-12 flex items-center justify-center">
                   {isSpeaking ? (
                      <div className="flex space-x-1 items-end h-6">
                        {[1, 2, 3, 4, 3, 2, 1].map((h, i) => (
                          <div key={i} className="w-1 bg-indigo-400 rounded-full animate-pulse" style={{ height: `${h * 10}%`, animationDelay: `${i * 0.1}s` }}></div>
                        ))}
                      </div>
                   ) : isListening ? (
                      <div className="w-3 h-3 bg-emerald-500 rounded-full animate-ping"></div>
                   ) : (
                      <svg className="w-8 h-8 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                   )}
                 </div>
              </div>

              <button 
                onClick={endSession}
                className="p-5 bg-red-600/10 border border-red-500/20 text-red-500 rounded-2xl hover:bg-red-600 hover:text-white transition-all shadow-xl"
                title="End Session"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            {/* Floating Live Transcript */}
            {showTranscript && (
              <div className="absolute right-0 top-0 bottom-0 w-[400px] bg-slate-900/80 backdrop-blur-2xl border-l border-slate-800 p-8 flex flex-col shadow-[-50px_0_100px_rgba(0,0,0,0.5)] animate-in slide-in-from-right duration-500">
                <div className="flex justify-between items-center mb-6">
                   <h3 className="font-black text-sm uppercase tracking-widest text-slate-500">Live Transcript</h3>
                   <button onClick={() => setShowTranscript(false)} className="text-slate-500 hover:text-white">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                   </button>
                </div>
                <div ref={chatScrollRef} className="flex-1 overflow-y-auto space-y-6 chat-scroll pr-2">
                  {messages.map((m, idx) => (
                    <div key={idx} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`p-4 rounded-2xl text-xs font-medium leading-relaxed ${m.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-300 border border-slate-700'}`}>
                        {m.text}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* Intelligence Overlay (Bottom) */}
        <div className={`mt-auto transition-opacity duration-1000 ${isLiveActive ? 'opacity-30' : 'opacity-100'}`}>
           <div className="px-10 py-6 bg-slate-900/60 backdrop-blur-2xl rounded-3xl border border-slate-800 flex items-center space-x-6">
             <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Knowledge Grounded</span>
                <p className="text-sm font-bold text-indigo-400">{documents.length} Materials Loaded & Indexed</p>
             </div>
             <div className="h-8 w-px bg-slate-800"></div>
             <div className="flex -space-x-3">
                {documents.slice(0, 3).map((doc, i) => (
                  <div key={i} className="w-10 h-10 rounded-xl border-4 border-slate-950 bg-slate-800 flex items-center justify-center text-[10px] font-black" title={doc.name}>
                    {doc.name.charAt(0).toUpperCase()}
                  </div>
                ))}
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

