        <div className="p-8 border-t border-slate-800 bg-slate-950/20">
           <div className={`w-full h-12 rounded-2xl bg-slate-950 border transition-all flex items-center px-4 ${isListening ? 'border-emerald-500/40 shadow-emerald-500/10' : 'border-slate-800 opacity-50'}`}>
