          {currentTranscription && (
            <div className="flex justify-start animate-in fade-in duration-300">
               <div className="max-w-[90%] p-4 bg-slate-800/40 border border-slate-700/20 rounded-[1.5rem] rounded-tl-none text-[12px] text-slate-400 italic leading-relaxed">
                 {currentTranscription}...
