import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-8 space-y-6 min-h-[50vh]">
        <div className="w-20 h-20 bg-slate-900 rounded-full flex items-center justify-center border border-slate-800">
          <svg className="w-10 h-10 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div>
          <h2 className="text-xl font-bold">No Material Found</h2>
          <p className="text-slate-400 text-sm">Upload academic context to unlock exams.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-6 min-h-[50vh]">
        <div className="w-12 h-12 border-4 border-purple-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-lg font-medium animate-pulse text-purple-400">Synthesizing Mastery Exam...</p>
      </div>
    );
  }

  if (isCompleted) {
    return (
      <div className="max-w-xl mx-auto text-center space-y-6 py-8 animate-in zoom-in-95 duration-500">
        <div className="relative inline-block">
          <svg className="w-24 h-24 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </div>
        <div>
          <h2 className="text-3xl font-black mb-2">Performance Report</h2>
          <p className="text-slate-400 font-bold">Score: {score} / {questions.length}</p>
        </div>
        <div className="bg-slate-900/50 p-6 rounded-[2rem] border border-slate-800 shadow-xl">
          <h3 className="font-black text-indigo-400 mb-3 uppercase tracking-widest text-[10px]">Academic Insight</h3>
          <p className="text-xs text-slate-400 leading-relaxed italic">
            "Your understanding of the grounded material is solid. Focus on the advanced mastery questions to bridge the gap between core theory and applied concepts."
          </p>
        </div>
        <div className="flex flex-col sm:flex-row items-center justify-center gap-4 pt-4">
          <button onClick={startExam} className="w-full sm:w-auto px-10 py-4 bg-slate-800 border border-slate-700 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-700 transition-all">Retake Exam</button>
          <button 
            onClick={() => onNavigateToFlashcards(incorrectTopics.join('; '))}
            className="w-full sm:w-auto px-10 py-4 bg-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 transition-all shadow-lg"
          >
            Review Weaknesses (Flashcards)
          </button>
        </div>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-2xl mx-auto space-y-6 py-4 animate-in slide-in-from-bottom-4 duration-500">
        <div className="flex justify-between items-center text-[10px] font-black text-slate-500 uppercase tracking-widest">
          <span>Module Mastery Check: {currentIdx + 1} / {questions.length}</span>
          <span className="text-emerald-400">Current Score: {score}</span>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] p-8 space-y-8 shadow-2xl">
          <h3 className="text-xl font-bold leading-snug text-slate-100">{q.question}</h3>

          <div className="space-y-3">
            {q.options.map((opt, i) => (
              <button 
                key={i}
                onClick={() => setSelectedAnswer(i)}
                className={`
                  w-full text-left p-5 rounded-2xl border transition-all duration-300
                  ${selectedAnswer === i 
                    ? 'bg-purple-600/20 border-purple-500 text-white shadow-lg' 
                    : 'bg-slate-800/20 border-slate-700/50 text-slate-400 hover:border-slate-500'}
                `}
              >
                <div className="flex items-center space-x-4">
                  <span className={`w-8 h-8 rounded-full flex items-center justify-center text-[10px] font-black ${selectedAnswer === i ? 'bg-purple-500 text-white' : 'bg-slate-700'}`}>
                    {String.fromCharCode(65 + i)}
                  </span>
                  <span className="text-sm font-medium">{opt}</span>
                </div>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-end">
          <button 
            disabled={selectedAnswer === null}
            onClick={handleNext}
            className={`px-12 py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] transition-all ${selectedAnswer !== null ? 'bg-indigo-600 text-white shadow-xl hover:scale-105' : 'bg-slate-800 text-slate-600 cursor-not-allowed'}`}
          >
            {currentIdx === questions.length - 1 ? 'Finalize Exam' : 'Next Question'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center space-y-8 min-h-[50vh]">
      <div className="text-center max-w-md space-y-4">
        <h2 className="text-3xl font-black bg-gradient-to-r from-purple-400 to-indigo-400 bg-clip-text text-transparent">Mastery Exam Center</h2>
        <p className="text-slate-400 text-sm leading-relaxed font-medium">Generate a precision exam based on your current session and relevant academic principles.</p>
      </div>
      <button 
        onClick={startExam}
        className="group relative px-12 py-5 bg-purple-600 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all hover:scale-105 active:scale-95 shadow-2xl shadow-purple-600/20"
      >
        Deploy Mastery Exam
      </button>
    </div>
  );
};

export default ExamMode;

import React, { useState, useEffect } from 'react';
import { PDFDocument, FlashCard } from '../types';
import { generateFlashcards } from '../services/geminiService';

interface FlashcardsViewProps {
  documents: PDFDocument[];
  weaknesses?: string;
}

const FlashcardsView: React.FC<FlashcardsViewProps> = ({ documents, weaknesses = "" }) => {
  const [cards, setCards] = useState<FlashCard[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (documents.length > 0) {
      loadCards();
    }
  }, [documents]);

  const loadCards = async () => {
    setIsLoading(true);
    try {
      const context = documents.map(d => d.content).join('\n');
      const generated = await generateFlashcards(context, weaknesses);
      setCards(generated);
      setCurrentIdx(0);
      setFlipped(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleNext = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev + 1) % cards.length);
    }, 150);
  };

  const handlePrev = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev - 1 + cards.length) % cards.length);
    }, 150);
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] text-center p-8">
         <h2 className="text-2xl font-black text-slate-500 uppercase tracking-widest">No Study Material</h2>
         <p className="text-slate-600 mt-2">Upload a PDF to generate personalized flashcards.</p>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] space-y-6">
        <div className="w-16 h-16 border-t-4 border-indigo-500 border-solid rounded-full animate-spin"></div>
        <p className="text-lg font-black text-indigo-400 animate-pulse tracking-widest uppercase text-xs">Generating Targeted Flashcards...</p>
      </div>
    );
  }

  if (cards.length === 0) return null;

  const card = cards[currentIdx];

  return (
    <div className="max-w-3xl mx-auto py-12 px-6 flex flex-col items-center space-y-12 animate-in fade-in duration-500">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-black uppercase tracking-tighter">Active Recall Center</h2>
        <p className="text-slate-500 font-bold text-xs tracking-widest uppercase">
          {weaknesses ? 'Focused on Weak Topics' : 'Session Mastery Overview'}
        </p>
      </div>

      <div 
        className="group relative w-full h-[400px] [perspective:1000px] cursor-pointer"
        onClick={() => setFlipped(!flipped)}
      >
        <div className={`relative w-full h-full transition-all duration-500 [transform-style:preserve-3d] ${flipped ? '[transform:rotateY(180deg)]' : ''}`}>
          {/* Front */}
          <div className="absolute inset-0 bg-slate-900 border-2 border-slate-800 rounded-[3rem] p-12 flex flex-col items-center justify-center text-center shadow-2xl [backface-visibility:hidden]">
            <span className="absolute top-8 text-[10px] font-black text-indigo-500 uppercase tracking-[0.3em]">Question</span>
            <p className="text-2xl font-bold text-slate-100 leading-relaxed">{card.front}</p>
            <span className="absolute bottom-8 text-[10px] font-bold text-slate-600 uppercase tracking-widest">Tap to reveal answer</span>
          </div>

          {/* Back */}
          <div className="absolute inset-0 bg-indigo-600 border-2 border-indigo-400 rounded-[3rem] p-12 flex flex-col items-center justify-center text-center shadow-2xl [transform:rotateY(180deg)] [backface-visibility:hidden]">
            <span className="absolute top-8 text-[10px] font-black text-indigo-100 uppercase tracking-[0.3em]">Answer</span>
            <p className="text-2xl font-bold text-white leading-relaxed">{card.back}</p>
            <span className="absolute bottom-8 text-[10px] font-bold text-indigo-200 uppercase tracking-widest">Tap to flip back</span>
          </div>
        </div>
      </div>

      <div className="flex items-center space-x-12">
        <button onClick={handlePrev} className="p-6 bg-slate-900 border border-slate-800 rounded-full hover:bg-slate-800 transition-all active:scale-90">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
        </button>
        <span className="text-sm font-black text-slate-600 tracking-widest">{currentIdx + 1} / {cards.length}</span>
        <button onClick={handleNext} className="p-6 bg-slate-900 border border-slate-800 rounded-full hover:bg-slate-800 transition-all active:scale-90">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>

      <button 
        onClick={loadCards}
        className="px-12 py-5 bg-slate-800 border border-slate-700 text-slate-300 rounded-2xl font-black text-[10px] uppercase tracking-[0.3em] hover:bg-slate-700 transition-all"
      >
        Regenerate Cards
      </button>
    </div>
  );
};

export default FlashcardsView;

