                    <h3 className="text-2xl font-black mb-3">Intelligence Hub</h3>
                    <p className="text-slate-400 text-sm leading-relaxed mb-6">Ground your tutor in your personal notes, research papers, or textbooks.</p>
                  </div>
                  <div className={`bg-slate-900 p-10 rounded-[2rem] border border-slate-800 transition-all cursor-pointer ${documents.length === 0 ? 'opacity-50' : 'hover:border-purple-500/50'}`} onClick={() => documents.length > 0 ? setActiveView(AppView.EXAM_MODE) : tryEnterTutoring()}>
                    <div className="w-14 h-14 bg-purple-500/10 text-purple-400 rounded-2xl flex items-center justify-center mb-8">{UI_ICONS.Exam}</div>
                    <h3 className="text-2xl font-black mb-3">Exam Mode</h3>
                    <p className="text-slate-400 text-sm leading-relaxed mb-6">Simulate exam conditions using questions from your grounded materials.</p>
