import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-8 space-y-6 min-h-[50vh]">
        <div className="w-20 h-20 bg-slate-900 rounded-full flex items-center justify-center border border-slate-800">
          <svg className="w-10 h-10 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div>
          <h2 className="text-xl font-bold">No Material Found</h2>
          <p className="text-slate-400 text-sm">Upload academic context to unlock exams.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-6 min-h-[50vh]">
        <div className="w-12 h-12 border-4 border-purple-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-lg font-medium animate-pulse text-purple-400 font-black uppercase tracking-widest text-xs">Synthesizing Mastery Exam...</p>
      </div>
    );
  }

  if (isCompleted) {
    return (
      <div className="max-w-xl mx-auto text-center space-y-8 py-8 animate-in zoom-in-95 duration-500">
        <div className="relative inline-block">
          <div className="absolute inset-0 bg-emerald-500 blur-2xl opacity-20 animate-pulse"></div>
          <svg className="w-24 h-24 text-emerald-500 relative" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </div>
        <div>
          <h2 className="text-4xl font-black mb-2 tracking-tighter">Session Results</h2>
          <p className="text-slate-400 font-bold text-lg">Mastery achieved: {Math.round((score / questions.length) * 100)}%</p>
        </div>
        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group text-left">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
            <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </div>
          <h3 className="font-black text-indigo-400 mb-4 uppercase tracking-[0.2em] text-[10px]">Tutor's Evaluation</h3>
          <p className="text-sm text-slate-300 leading-relaxed font-medium">
            {score === questions.length 
              ? "Flawless performance. You've fully grounded the knowledge from this module. I recommend moving to the next chapter or reinforcing via rapid flashcards."
              : `Good progress. You struggled with ${incorrectTopics.length} core concepts. I've highlighted these as critical weaknesses for your next flashcard session.`}
          </p>
        </div>
        <div className="flex flex-col gap-4 pt-4">
          <button 
            onClick={() => onNavigateToFlashcards(incorrectTopics.join('; '))}
            className="w-full py-5 bg-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/30 flex items-center justify-center space-x-3"
          >
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2" /></svg>
             <span>Review Weaknesses with Flashcards</span>
          </button>
          <button onClick={startExam} className="w-full py-5 bg-slate-800 border border-slate-700 text-slate-400 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-700 transition-all">Retake Mastery Exam</button>
        </div>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-2xl mx-auto space-y-6 py-4 animate-in slide-in-from-bottom-4 duration-500">
        <div className="flex justify-between items-center text-[10px] font-black text-slate-500 uppercase tracking-widest">
          <span>Question {currentIdx + 1} / {questions.length}</span>
          <span className="text-emerald-400">Current Score: {score}</span>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] p-10 space-y-10 shadow-2xl">
          <h3 className="text-2xl font-black leading-tight text-slate-100">{q.question}</h3>

          <div className="grid grid-cols-1 gap-4">
            {q.options.map((opt, i) => (
              <button 
                key={i}
                onClick={() => setSelectedAnswer(i)}
                className={`
                  w-full text-left p-6 rounded-2xl border transition-all duration-300 flex items-center space-x-5
                  ${selectedAnswer === i 
                    ? 'bg-purple-600/10 border-purple-500 text-white ring-1 ring-purple-500/50 shadow-xl shadow-purple-900/10' 
                    : 'bg-slate-800/20 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-800/40'}
                `}
              >
                <span className={`w-8 h-8 rounded-full flex items-center justify-center text-[10px] font-black transition-colors ${selectedAnswer === i ? 'bg-purple-600 text-white' : 'bg-slate-800 border border-slate-700 text-slate-500'}`}>
                  {String.fromCharCode(65 + i)}
                </span>
                <span className="text-sm font-bold tracking-tight">{opt}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-end pt-4">
          <button 
            disabled={selectedAnswer === null}
            onClick={handleNext}
            className={`px-16 py-5 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] transition-all shadow-2xl ${selectedAnswer !== null ? 'bg-indigo-600 text-white hover:bg-indigo-500 hover:scale-105 active:scale-95 shadow-indigo-600/20' : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'}`}
          >
            {currentIdx === questions.length - 1 ? 'Finalize Mastery Check' : 'Proceed to Next Task'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center space-y-10 min-h-[50vh] text-center max-w-lg mx-auto">
      <div className="p-8 bg-indigo-600/5 rounded-full border border-indigo-500/10 mb-2">
         <svg className="w-16 h-16 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
      </div>
      <div className="space-y-4">
        <h2 className="text-4xl font-black bg-gradient-to-r from-white to-slate-500 bg-clip-text text-transparent tracking-tighter">Exam Mastery Center</h2>
        <p className="text-slate-400 text-lg leading-relaxed font-medium">Generate a targeted mastery exam derived strictly from your active academic materials and tutor dialogue.</p>
      </div>
      <button 
        onClick={startExam}
        className="group relative px-16 py-6 bg-purple-600 rounded-[2.5rem] font-black text-xs uppercase tracking-[0.3em] transition-all hover:scale-105 active:scale-95 shadow-2xl shadow-purple-600/40 hover:bg-purple-500"
      >
        Deploy Syllabus Exam
      </button>
    </div>
  );
};

export default ExamMode;

import React, { useState, useEffect, useRef } from 'react';
import Avatar from './Avatar';
import { Message, PDFDocument } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decode, decodeAudioData } from '../services/geminiService';
import { KHULA_SYSTEM_INSTRUCTION } from '../constants';

interface TutoringViewProps {
  document: PDFDocument;
  onNavigateToExam: () => void;
}

const TutoringView: React.FC<TutoringViewProps> = ({ document, onNavigateToExam }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isThinking, setIsThinking] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isLiveActive, setIsLiveActive] = useState(false);
  const [currentTranscription, setCurrentTranscription] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputNodeRef = useRef<GainNode | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const chatScrollRef = useRef<HTMLDivElement>(null);
  const sessionRef = useRef<any>(null);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [messages, currentTranscription]);

  useEffect(() => {
    startSession();
    return () => {
      if (sessionRef.current) {
        sessionRef.current.close();
      }
    };
  }, [document.id]);

  const startSession = async () => {
    if (isLiveActive) return;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputAudioContext;
      outputNodeRef.current = outputAudioContext.createGain();
      outputNodeRef.current.connect(outputAudioContext.destination);

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const session = await ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsLiveActive(true);
            setIsListening(true);

            const mediaSource = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              session.sendRealtimeInput({ media: pcmBlob });
            };
            mediaSource.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);

            // Immediate professional introduction
            session.sendRealtimeInput({ 
              text: `MANDATORY SESSION START: Introduce yourself as Khula AI Tutor. 
              State clearly that you have analyzed the student's document '${document.name}'. 
              Briefly restate the document's main focus in one professional sentence. 
              Then, ask: 'I'm ready to solve any question from this material with you step-by-step. What topic or problem should we start with?'` 
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.modelTurn) {
              setIsThinking(false);
            } else if (message.serverContent?.turnComplete) {
              setIsThinking(false);
              if (currentTranscription.trim()) {
                setMessages(prev => [...prev, { role: 'model', text: currentTranscription, timestamp: new Date() }]);
              }
              setCurrentTranscription('');
            } else if (message.serverContent?.inputTranscription) {
              setIsThinking(true);
              setCurrentTranscription(prev => prev + message.serverContent.inputTranscription.text);
            }

            if (message.serverContent?.outputTranscription) {
              setCurrentTranscription(prev => prev + message.serverContent.outputTranscription.text);
            }

            if (message.serverContent?.interrupted) {
              for (const source of sourcesRef.current.values()) {
                try { source.stop(); } catch(e) {}
              }
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsSpeaking(false);
              setIsThinking(false);
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsSpeaking(true);
              setIsThinking(false);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
              const source = outputAudioContext.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputNodeRef.current!);

              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              });

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error('Live session error:', e);
            setIsLiveActive(false);
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsListening(false);
            setIsSpeaking(false);
            setIsThinking(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          outputAudioTranscription: {},
          inputAudioTranscription: {},
          systemInstruction: KHULA_SYSTEM_INSTRUCTION + ` \n\nCURRENT ACADEMIC CONTENT FOR STUDY: ${document.content}`,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
        }
      });

      sessionRef.current = session;
    } catch (err) {
      console.error("Critical error starting tutor session:", err);
    }
  };

  const endSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden relative">
      {/* Immersive Tutoring Sidebar */}
      <div className="w-[400px] flex flex-col bg-slate-900 border-r border-slate-800 shadow-2xl z-20">
        <div className="p-8 border-b border-slate-800 flex justify-between items-center bg-slate-900/50">
          <div>
            <h3 className="text-xl font-black flex items-center space-x-3">
              <span className={`w-3 h-3 rounded-full ${isLiveActive ? 'bg-emerald-500 animate-pulse' : 'bg-slate-700'}`}></span>
              <span>Tutoring Room</span>
            </h3>
            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">Material: {document.name}</p>
          </div>
        </div>

        <div ref={chatScrollRef} className="flex-1 overflow-y-auto p-8 space-y-6 chat-scroll scroll-smooth">
          {messages.length === 0 && !currentTranscription && (
            <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center space-y-4 opacity-40">
              <div className="p-8 bg-slate-950 rounded-[2rem] border border-slate-800">
                <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              </div>
              <p className="text-xs font-black uppercase tracking-widest leading-relaxed text-center">Khula is syncing with your syllabus...</p>
            </div>
          )}

          {messages.map((m, idx) => (
            <div key={idx} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className={`max-w-[90%] p-4 rounded-[1.5rem] text-[12px] font-medium leading-relaxed shadow-lg ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700/50'}`}>
                {m.text}
              </div>
            </div>
          ))}

          {currentTranscription && (
            <div className="flex justify-start animate-in fade-in duration-300">
               <div className="max-w-[90%] p-4 bg-slate-800/40 border border-slate-700/20 rounded-[1.5rem] rounded-tl-none text-[12px] text-slate-400 italic leading-relaxed whitespace-pre-wrap">
                 {currentTranscription}...
               </div>
            </div>
          )}
        </div>

        <div className="p-6 border-t border-slate-800 bg-slate-950/20">
           <button 
             onClick={() => {
               endSession();
               onNavigateToExam();
             }}
             className="w-full py-5 bg-purple-600 text-white rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] transition-all flex items-center justify-center space-x-3 shadow-2xl shadow-purple-600/30 hover:bg-purple-500 hover:scale-[1.02] active:scale-95"
           >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             <span>Enter Exam Mastery Center</span>
           </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center relative bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-600/10 via-slate-950 to-slate-950">
        <div className="w-full max-w-xl mb-12 transform scale-125 transition-all duration-1000">
           <Avatar isThinking={isThinking} isSpeaking={isSpeaking} isListening={isListening} />
        </div>

        <div className="flex items-center space-x-12 mt-20">
