  const tryEnterTutoring = () => {
    if (documents.length === 0) {
      setErrorMsg("Upload a PDF to activate the Tutoring Engine.");
      setActiveView(AppView.DOCUMENTS);
      setTimeout(() => setErrorMsg(null), 4000);
      return;
