  const isImmersive = activeView === AppView.TUTORING;

  return (
    <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden">
      {!isImmersive && (
        <aside className="w-72 bg-[#0b0f1a] border-r border-white/5 flex flex-col z-30 shadow-2xl">
          <div className="p-8 pb-10">
            <div className="flex items-center space-x-3 mb-1">
              <div className="bg-indigo-600 w-10 h-10 flex items-center justify-center rounded-xl text-white font-black shadow-lg shadow-indigo-600/30">K</div>
              <h1 className="text-2xl font-black tracking-tight bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">Khula</h1>
            </div>
            <div className="flex items-center space-x-2 px-1">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <p className="text-[9px] font-bold text-slate-500 uppercase tracking-[0.2em]">Academic Neural Engine</p>
            </div>
          </div>

          <nav className="flex-1 px-4 space-y-1.5 overflow-y-auto chat-scroll">
            {navItems.map(item => {
              const isDisabled = item.requiresDoc && documents.length === 0;
              const isActive = activeView === item.id;
              return (
                <button
                  key={item.id}
                  onClick={() => isDisabled ? tryEnterTutoring() : setActiveView(item.id)}
                  className={`
                    w-full flex items-center justify-between px-4 py-3.5 rounded-xl text-[13px] font-semibold transition-all group
                    ${isActive 
                      ? 'bg-indigo-600/10 text-indigo-400 border border-indigo-500/20' 
                      : isDisabled 
                        ? 'text-slate-600 cursor-not-allowed opacity-40'
                        : 'text-slate-400 hover:bg-white/5 hover:text-white'}
                  `}
                >
                  <div className="flex items-center space-x-3">
                    <span className={`${isActive ? 'text-indigo-400' : 'text-slate-500 group-hover:text-indigo-400'}`}>
                      {item.icon}
                    </span>
                    <span>{item.label}</span>
                  </div>
                  {isActive && <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,1)]"></div>}
                </button>
              );
            })}
          </nav>

          <div className="p-4 m-4 rounded-2xl bg-[#0f172a] border border-white/5">
             <div className="flex items-center justify-between mb-3 px-1">
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Storage</span>
               <span className="text-[10px] font-bold text-indigo-400">{documents.length}/5</span>
             </div>
             <div className="w-full bg-slate-900 h-1.5 rounded-full overflow-hidden mb-2">
               <div className="bg-indigo-500 h-full transition-all duration-700" style={{ width: `${(documents.length / 5) * 100}%` }}></div>
             </div>
             <div className="flex items-center justify-between text-[10px] font-bold text-slate-500 px-1">
                <span>Free Plan</span>
                <button onClick={() => setActiveView(AppView.PRICING)} className="text-indigo-400 hover:text-indigo-300">Upgrade</button>
             </div>
          </div>
        </aside>
      )}

      <main className="flex-1 flex flex-col min-w-0 bg-[#020617] overflow-hidden">
        {errorMsg && (
          <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[60] bg-red-500 text-white px-6 py-3 rounded-xl shadow-2xl font-bold text-xs uppercase tracking-widest animate-in fade-in slide-in-from-top-4 duration-300 flex items-center space-x-3">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            <span>{errorMsg}</span>
          </div>
        )}

        {!isImmersive && (
          <header className="h-20 px-10 flex items-center justify-between border-b border-white/5 bg-[#020617]/80 backdrop-blur-md z-20">
            <div className="flex flex-col">
               <h2 className="text-xl font-black capitalize tracking-tight text-white">{activeView.replace('_', ' ')}</h2>
               <p className="text-[11px] text-slate-500 font-bold uppercase tracking-widest">Grounded Digital Environment</p>
            </div>
            <div className="flex items-center space-x-6">
               <div className="hidden md:flex flex-col items-end">
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-0.5">Academic Status</span>
                  <div className="flex items-center space-x-2">
                    <span className="text-xs font-bold text-emerald-400 bg-emerald-500/10 px-2 py-0.5 rounded-md border border-emerald-500/20">Synced</span>
                    <span className="text-xs font-bold text-indigo-400 bg-indigo-500/10 px-2 py-0.5 rounded-md border border-indigo-500/20">{subscription}</span>
                  </div>
               </div>
               <div className="w-10 h-10 rounded-xl bg-slate-800 border border-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors cursor-pointer relative">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                  <div className="absolute top-2.5 right-2.5 w-2 h-2 bg-indigo-500 rounded-full border-2 border-slate-800"></div>
               </div>
            </div>
          </header>
        )}

        <div className={`flex-1 overflow-y-auto chat-scroll ${isImmersive ? "" : "p-10"}`}>
          {activeView === AppView.DASHBOARD && (
            <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in duration-700">
               <div className="relative overflow-hidden bg-indigo-600 rounded-[2rem] p-10 md:p-14 text-white shadow-2xl premium-glow">
                  <div className="relative z-10 max-w-2xl space-y-6">
                    <div className="inline-block px-3 py-1 bg-white/10 backdrop-blur-md rounded-lg text-[10px] font-black uppercase tracking-[0.2em] border border-white/10">Welcome back, Scholar</div>
                    <h2 className="text-4xl md:text-5xl font-black leading-tight tracking-tight">Ground Your AI, <br/><span className="text-indigo-200">Master Your Syllabus.</span></h2>
                    <p className="text-indigo-100 text-base md:text-lg font-medium opacity-80 leading-relaxed max-w-lg">
                      {documents.length > 0 
                        ? `Your intelligence hub is live with ${documents.length} materials. Ready for a deep-dive session?`
                        : "Khula isn't just a chatbot—it's your personal tutor grounded strictly in your own textbooks, notes, and curriculum."}
                    </p>
                    <div className="flex flex-wrap gap-4 pt-2">
                      <button 
                        onClick={() => setActiveView(AppView.DOCUMENTS)}
                        className="px-8 py-3.5 bg-white text-indigo-700 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 hover:scale-[1.03] transition-all shadow-xl shadow-black/10 active:scale-95"
                      >
                        {documents.length > 0 ? 'Open Library' : 'Ground Your First PDF'}
                      </button>
                      <button 
                         onClick={tryEnterTutoring}
                         className="px-8 py-3.5 bg-indigo-500 text-white border border-indigo-400/30 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-400 transition-all active:scale-95"
                      >
                        Launch Tutor
