                    { id: AppView.EXAM_MODE, icon: UI_ICONS.Exam, color: 'purple', title: 'Mastery Exams', desc: 'Synthesize custom practice exams strictly from your uploaded course materials.' },
                    { id: AppView.FLASHCARDS, icon: UI_ICONS.Flashcards, color: 'emerald', title: 'Active Recall', desc: 'Deep-code concepts into memory with cards focused on your identified weak areas.' },
