          {activeView === AppView.DOCUMENTS && (
            <PDFManager 
              documents={documents} 
              onUpload={handleUpload} 
              onDelete={handleDeleteDoc}
              onSelect={handleSelectDoc}
              selectedDocId={selectedDocId}
            />
          )}

          {activeView === AppView.TUTORING && selectedDocument && (
            <div className="h-full relative animate-in fade-in duration-500">
              <button 
                onClick={() => setActiveView(AppView.DASHBOARD)}
                className="absolute top-6 left-6 z-[100] p-3 bg-slate-900/80 hover:bg-slate-800 border border-white/10 rounded-xl text-slate-300 transition-all backdrop-blur-md shadow-2xl hover:scale-105 active:scale-95"
                title="Exit Tutoring Room"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
              </button>
              <TutoringView 
                document={selectedDocument} 
                onNavigateToExam={() => setActiveView(AppView.EXAM_MODE)} 
              />
            </div>
          )}

          {activeView === AppView.EXAM_MODE && (
            <ExamMode 
              documents={documents} 
              onNavigateToFlashcards={handleNavigateToFlashcards}
            />
          )}

          {activeView === AppView.FLASHCARDS && (
            <FlashcardsView 
              documents={documents} 
              weaknesses={examWeaknesses} 
            />
          )}

          {activeView === AppView.ANALYTICS && <AnalyticsView />}
          {activeView === AppView.PRICING && <PricingTiers onSelect={handleSelectPlan} />}
        </div>
      </main>
    </div>
  );
};

