import React, { useState } from 'react';
import { PDFDocument } from '../types';
import { analyzePDF } from '../services/geminiService';

interface PDFManagerProps {
  onUpload: (doc: PDFDocument) => void;
  documents: PDFDocument[];
  onDelete: (id: string) => void;
  onSelect: (id: string) => void;
  selectedDocId: string | null;
}

const PDFManager: React.FC<PDFManagerProps> = ({ onUpload, documents, onDelete, onSelect, selectedDocId }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState("");

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setUploadProgress("Analyzing Material Intelligence...");

    try {
      const result = await analyzePDF(file);

      const newDoc: PDFDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        content: result.fullContent,
        uploadDate: new Date(),
        summary: result.summary,
        topics: result.topics
      };

      onUpload(newDoc);
    } catch (err) {
      console.error("PDF Analysis Failed:", err);
      alert("Failed to analyze the material. Please verify the PDF format.");
    } finally {
      setIsUploading(false);
      setUploadProgress("");
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-12 animate-in fade-in duration-700">
      <div className="bg-[#0b0f1a] rounded-[2.5rem] border border-white/5 p-12 md:p-16 text-center space-y-8 relative overflow-hidden group shadow-2xl">
        <div className="absolute inset-0 bg-indigo-500/5 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
        <div className="relative inline-flex p-5 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 group-hover:scale-110 transition-all">
          <svg className="w-10 h-10 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
        </div>
        <div className="space-y-3 max-w-xl mx-auto relative z-10">
          <h2 className="text-3xl font-black tracking-tight text-white">Academic Knowledge Input</h2>
          <p className="text-slate-500 text-sm md:text-base leading-relaxed font-medium">Ground your tutor in your personal context. Upload syllabus-aligned materials to index them into the neural tutoring engine.</p>
        </div>

        {isUploading ? (
          <div className="flex flex-col items-center space-y-4 pt-4">
            <div className="flex space-x-1.5">
              <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce"></div>
            </div>
            <p className="text-indigo-400 font-black text-[10px] uppercase tracking-[0.2em]">{uploadProgress}</p>
          </div>
        ) : (
          <label className="relative inline-block px-10 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-black text-xs uppercase tracking-widest cursor-pointer transition-all active:scale-95 shadow-xl shadow-indigo-600/20">
            Ground New PDF
            <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} disabled={isUploading} />
          </label>
        )}
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Knowledge Library</h3>
          <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">{documents.length} Grounded Modules</span>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-12">
          {documents.length === 0 && !isUploading && (
            <div className="col-span-full py-24 text-center border border-dashed border-white/5 rounded-[2rem] bg-white/[0.01]">
              <p className="text-xs font-bold text-slate-600 uppercase tracking-[0.2em]">Awaiting Knowledge Grounding...</p>
            </div>
          )}
          {documents.map(doc => (
            <div key={doc.id} className={`bg-[#0b0f1a] border ${selectedDocId === doc.id ? 'border-indigo-500 ring-4 ring-indigo-500/10' : 'border-white/5'} rounded-2xl p-6 flex flex-col group transition-all hover:bg-white/[0.02] hover:border-white/10 shadow-xl`}>
              <div className="flex items-start justify-between mb-5">
                <div className="flex items-center space-x-4">
                  <div className={`p-3 rounded-xl transition-colors ${selectedDocId === doc.id ? 'bg-indigo-600 text-white' : 'bg-[#0f172a] text-slate-500'}`}>
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                  </div>
                  <div className="min-w-0">
                    <h4 className="font-black text-slate-100 truncate text-sm" title={doc.name}>{doc.name}</h4>
                    <p className="text-[9px] text-emerald-500 font-bold uppercase tracking-widest mt-0.5">Neural Linked</p>
                  </div>
                </div>
                <button onClick={() => onDelete(doc.id)} className="p-2 text-slate-700 hover:text-red-500 transition-colors" title="Remove Grounding">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <div className="flex-1 space-y-4">
                 <p className="text-[11px] text-slate-500 font-medium line-clamp-2 leading-relaxed h-8">{doc.summary}</p>
                 <div className="flex flex-wrap gap-1.5 h-10 overflow-hidden">
                    {doc.topics?.slice(0, 3).map(t => (
                      <span key={t} className="px-2 py-0.5 bg-slate-900 text-slate-400 text-[8px] font-bold rounded border border-white/5 uppercase tracking-tighter max-w-full truncate">{t}</span>
                    ))}
                 </div>
              </div>

              <button 
                onClick={() => onSelect(doc.id)}
                className={`w-full mt-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all
                  ${selectedDocId === doc.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'bg-[#0f172a] text-slate-400 hover:text-white hover:bg-slate-800'}
                `}
              >
                {selectedDocId === doc.id ? 'Session Ready' : 'Initialize Session'}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

