import React, { useState, useEffect, useRef } from 'react';
import Avatar from './Avatar';
import { Message, PDFDocument } from '../types';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { createPcmBlob, decode, decodeAudioData } from '../services/geminiService';
import { KHULA_SYSTEM_INSTRUCTION } from '../constants';

interface TutoringViewProps {
  document: PDFDocument;
  onNavigateToExam: () => void;
}

const TutoringView: React.FC<TutoringViewProps> = ({ document, onNavigateToExam }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isThinking, setIsThinking] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isLiveActive, setIsLiveActive] = useState(false);
  const [currentTranscription, setCurrentTranscription] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputNodeRef = useRef<GainNode | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const chatScrollRef = useRef<HTMLDivElement>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);

  useEffect(() => {
    if (chatScrollRef.current) {
      chatScrollRef.current.scrollTop = chatScrollRef.current.scrollHeight;
    }
  }, [messages, currentTranscription]);

  useEffect(() => {
    startSession();
    return () => {
      if (sessionPromiseRef.current) {
        sessionPromiseRef.current.then(session => session.close());
      }
    };
  }, [document.id]);

  const startSession = async () => {
    if (isLiveActive) return;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputAudioContext;
      outputNodeRef.current = outputAudioContext.createGain();
      outputNodeRef.current.connect(outputAudioContext.destination);

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      let activeSessionPromise: Promise<any>;

      activeSessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsLiveActive(true);
            setIsListening(true);

            const mediaSource = inputAudioContext.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              activeSessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            mediaSource.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContext.destination);

            activeSessionPromise.then((session) => {
              session.sendRealtimeInput({ 
                text: `MANDATORY SESSION START: 
                1. Introduce yourself as Khula AI Tutor.
                2. Inform the student: 'I have successfully analyzed "${document.name}" and fully mapped out its core syllabus.'
                3. Use the document summary: "${document.summary || 'Academic Resource Analysis complete.'}"
                4. Invite interaction professionally: 'We are ready to master these concepts. What specific topic or problem from this material should we tackle first?'` 
              });
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.modelTurn) {
              setIsThinking(false);
            } else if (message.serverContent?.turnComplete) {
              setIsThinking(false);
              if (currentTranscription.trim()) {
                setMessages(prev => [...prev, { role: 'model', text: currentTranscription, timestamp: new Date() }]);
              }
              setCurrentTranscription('');
            } else if (message.serverContent?.inputTranscription) {
              setIsThinking(true);
              setCurrentTranscription(prev => prev + message.serverContent.inputTranscription.text);
            }

            if (message.serverContent?.outputTranscription) {
              setCurrentTranscription(prev => prev + message.serverContent.outputTranscription.text);
            }

            if (message.serverContent?.interrupted) {
              for (const source of sourcesRef.current.values()) {
                try { source.stop(); } catch(e) {}
              }
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsSpeaking(false);
              setIsThinking(false);
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsSpeaking(true);
              setIsThinking(false);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioContext.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
              const source = outputAudioContext.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputNodeRef.current!);

              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              });

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e) => {
            console.error('Live session error:', e);
            setIsLiveActive(false);
          },
          onclose: () => {
            setIsLiveActive(false);
            setIsListening(false);
            setIsSpeaking(false);
            setIsThinking(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          outputAudioTranscription: {},
          inputAudioTranscription: {},
          systemInstruction: KHULA_SYSTEM_INSTRUCTION + ` \n\nCURRENT ACADEMIC CONTENT FOR STUDY: ${document.content}`,
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } }
        }
      });

      sessionPromiseRef.current = activeSessionPromise;
    } catch (err) {
      console.error("Critical error starting tutor session:", err);
    }
  };

  const endSession = () => {
    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then(session => session.close());
    }
  };

  return (
    <div className="flex h-screen bg-[#020617] overflow-hidden relative">
      {/* Immersive Sidebar */}
      <div className="w-[380px] hidden lg:flex flex-col bg-[#0b0f1a] border-r border-white/5 z-20 shadow-2xl overflow-hidden">
        <div className="p-8 border-b border-white/5 bg-white/[0.02]">
          <div className="flex items-center justify-between mb-4">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Session Analytics</span>
            <div className={`w-2 h-2 rounded-full ${isLiveActive ? 'bg-emerald-500 animate-pulse' : 'bg-slate-700'}`}></div>
          </div>
          <h3 className="text-xl font-black text-white leading-tight">Mastery Session</h3>
          <div className="flex items-center space-x-2 mt-2">
            <svg className="w-3.5 h-3.5 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest truncate">{document.name}</p>
          </div>
        </div>

        <div ref={chatScrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 chat-scroll scroll-smooth bg-slate-950/20">
          {messages.length === 0 && !currentTranscription && (
            <div className="h-full flex flex-col items-center justify-center text-center px-6 opacity-30">
              <div className="p-6 bg-slate-900 rounded-full mb-6 ring-1 ring-white/5">
                <svg className="w-8 h-8 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
              </div>
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Khula Neural Engine Online</p>
            </div>
          )}

          {messages.map((m, idx) => (
            <div key={idx} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className={`max-w-[90%] px-5 py-4 rounded-2xl text-[12px] font-medium leading-relaxed shadow-xl ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-900 text-slate-200 rounded-tl-none border border-white/5'}`}>
                {m.text}
              </div>
            </div>
          ))}

          {currentTranscription && (
            <div className="flex justify-start animate-in fade-in duration-300">
               <div className="max-w-[90%] px-5 py-4 bg-white/5 border border-white/5 rounded-2xl rounded-tl-none text-[12px] text-slate-400 italic leading-relaxed whitespace-pre-wrap">
                 {currentTranscription}
               </div>
            </div>
          )}
        </div>

        <div className="p-6 border-t border-white/5 bg-white/[0.01]">
           <button 
             onClick={() => {
               endSession();
               onNavigateToExam();
             }}
             className="w-full py-4 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center justify-center space-x-3 shadow-lg shadow-indigo-600/20 hover:bg-indigo-500 hover:scale-[1.02] active:scale-95"
           >
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             <span>Launch Exam Mode</span>
           </button>
        </div>
      </div>

      {/* Cinematic Main View */}
      <div className="flex-1 flex flex-col items-center justify-center relative bg-[radial-gradient(circle_at_center,_#0f172a_0%,_#020617_100%)]">
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')] opacity-10 pointer-events-none"></div>

        <div className="w-full max-w-lg mb-8 transform scale-110 lg:scale-125 transition-all duration-1000 z-10">
           <Avatar isThinking={isThinking} isSpeaking={isSpeaking} isListening={isListening} />
        </div>

        <div className="flex items-center space-x-12 mt-12 z-10">
          <div className={`p-8 rounded-full border-2 transition-all duration-700 shadow-2xl relative group ${isSpeaking ? 'border-indigo-500 bg-indigo-500/10 shadow-indigo-500/30' : isListening ? 'border-emerald-500 bg-emerald-500/10 shadow-emerald-500/30' : 'border-white/5 bg-white/5 backdrop-blur-md'}`}>
             {isListening && <div className="absolute inset-0 rounded-full border border-emerald-500 animate-ping opacity-20"></div>}
             <div className="w-12 h-12 flex items-center justify-center relative">
               {isSpeaking ? (
                  <div className="flex space-x-1 items-end h-6">
                    {[1, 2, 3, 4, 3, 2, 1, 2, 4, 3].map((h, i) => (
                      <div key={i} className="w-1 bg-indigo-400 rounded-full animate-pulse" style={{ height: `${h * 15}%`, animationDelay: `${i * 0.1}s` }}></div>
                    ))}
                  </div>
               ) : isListening ? (
                  <div className="w-4 h-4 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.8)]"></div>
               ) : (
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-slate-300 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
               )}
             </div>
          </div>

          <button onClick={endSession} className="p-6 bg-red-500/10 border border-red-500/20 text-red-500 rounded-2xl hover:bg-red-500 hover:text-white transition-all shadow-xl active:scale-90 group" title="End Session">
            <svg className="w-6 h-6 transform group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="absolute top-10 px-5 py-2.5 bg-slate-900/40 backdrop-blur-xl border border-white/5 rounded-full flex items-center space-x-3 shadow-2xl animate-in slide-in-from-top-4 duration-1000">
           <div className={`w-2 h-2 rounded-full animate-pulse ${isThinking ? 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.8)]' : 'bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.8)]'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">
             {isThinking ? 'Tutor Reflecting...' : 'Grounded Interaction Active'}
           </span>
        </div>

        <div className="absolute bottom-10 px-8 py-4 bg-white/[0.02] backdrop-blur-2xl border border-white/5 rounded-2xl flex items-center space-x-8 shadow-2xl animate-in slide-in-from-bottom-4 duration-1000">
           <div className="flex flex-col text-center">
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Knowledge Context</span>
              <span className="text-xs font-bold text-slate-200 tracking-tight">{document.name}</span>
           </div>
           <div className="w-px h-8 bg-white/5"></div>
           <div className="flex flex-col text-center">
              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Neural Voice</span>
              <span className="text-xs font-bold text-slate-200">Zephyr-Professional</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default TutoringView;

import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-12 space-y-6 min-h-[60vh] animate-in fade-in duration-700">
        <div className="w-20 h-20 bg-slate-900/50 rounded-full flex items-center justify-center border border-white/5">
          <svg className="w-10 h-10 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-xl font-black text-white">Neural Hub Empty</h2>
          <p className="text-slate-500 text-sm font-medium max-w-xs mx-auto">Upload academic context to generate syllabus-grounded mastery exams.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-8 min-h-[60vh] animate-in fade-in duration-500">
        <div className="relative">
          <div className="w-16 h-16 border-4 border-indigo-600/20 rounded-full"></div>
          <div className="absolute inset-0 w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
        <div className="text-center space-y-2">
          <p className="text-indigo-400 font-black text-[10px] uppercase tracking-[0.3em] animate-pulse">Synthesizing Mastery Data</p>
          <p className="text-slate-500 text-xs font-medium">Extracting core concepts for your evaluation...</p>
        </div>
      </div>
    );
  }

  if (isCompleted) {
    const percentage = Math.round((score / questions.length) * 100);
    return (
      <div className="max-w-xl mx-auto text-center space-y-10 py-12 animate-in zoom-in-95 duration-700">
        <div className="relative inline-block">
          <div className="absolute inset-0 bg-emerald-500 blur-3xl opacity-20 animate-pulse"></div>
          <div className="w-24 h-24 bg-emerald-500/10 border-2 border-emerald-500/30 rounded-full flex items-center justify-center relative">
            <svg className="w-12 h-12 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </div>
        </div>

        <div className="space-y-2">
          <h2 className="text-5xl font-black text-white tracking-tight leading-none">{percentage}%</h2>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Evaluation Proficiency Achieved</p>
        </div>

        <div className="bg-[#0b0f1a] border border-white/5 p-8 rounded-[2rem] shadow-2xl relative overflow-hidden text-left group">
          <div className="absolute -top-10 -right-10 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
            <svg className="w-40 h-40" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </div>
          <h3 className="font-black text-indigo-400 mb-4 uppercase tracking-[0.2em] text-[10px]">Neural Tutor Feedback</h3>
          <p className="text-sm text-slate-300 leading-relaxed font-medium relative z-10">
            {score === questions.length 
              ? "Exceptional retention. You've fully grounded the knowledge from these modules. Khula recommends progressing to advanced application or synthesizing a new curriculum block."
              : `Productive session. You encountered resistance in ${incorrectTopics.length} core conceptual areas. These have been flagged and mapped for your next active recall study session.`}
          </p>
        </div>

        <div className="flex flex-col gap-4">
          <button 
            onClick={() => onNavigateToFlashcards(incorrectTopics.join('; '))}
            className="w-full py-5 bg-indigo-600 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20 flex items-center justify-center space-x-3 active:scale-[0.98]"
          >
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2" /></svg>
             <span>Ground Weaknesses with Study Cards</span>
          </button>
          <button onClick={startExam} className="w-full py-5 bg-white/5 border border-white/5 text-slate-400 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] hover:bg-white/10 hover:text-white transition-all active:scale-[0.98]">Deploy New Exam Block</button>
        </div>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-3xl mx-auto space-y-8 py-4 animate-in fade-in slide-in-from-bottom-6 duration-700">
        <div className="flex justify-between items-end px-4">
          <div className="space-y-1">
             <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">Module Checkpoint</span>
             <h3 className="text-xs font-bold text-white">Question {currentIdx + 1} of {questions.length}</h3>
          </div>
          <div className="text-right space-y-1">
