          >
            {currentIdx === questions.length - 1 ? 'Analyze Final Results' : 'Lock Answer & Proceed'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center space-y-10 min-h-[60vh] text-center max-w-lg mx-auto py-12 animate-in fade-in duration-700">
      <div className="p-8 bg-indigo-600/10 rounded-[2rem] border border-indigo-500/20 mb-2 relative group">
