import React, { useState, useEffect } from 'react';
import { PDFDocument, FlashCard } from '../types';
import { generateFlashcards } from '../services/geminiService';

interface FlashcardsViewProps {
  documents: PDFDocument[];
  weaknesses?: string;
}

const FlashcardsView: React.FC<FlashcardsViewProps> = ({ documents, weaknesses = "" }) => {
  const [cards, setCards] = useState<FlashCard[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (documents.length > 0) {
      loadCards();
    }
  }, [documents]);

  const loadCards = async () => {
    setIsLoading(true);
    try {
      const context = documents.map(d => d.content).join('\n');
      const generated = await generateFlashcards(context, weaknesses);
      setCards(generated);
      setCurrentIdx(0);
      setFlipped(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleNext = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev + 1) % cards.length);
    }, 150);
  };

  const handlePrev = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev - 1 + cards.length) % cards.length);
    }, 150);
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-12 animate-in fade-in duration-700">
         <div className="p-8 bg-slate-900/50 rounded-full border border-white/5 mb-6 text-slate-700">
            <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2M8 7H6a2 2 0 00-2 2v10a2 2 0 01-2 2v-7a2 2 0 012-2h2m4.688-2.119l8 8m-1-7.9c.082.387.354.667.75.667h.5a.5.5 0 00.5-.5v-.5a.5.5 0 00-.5-.5h-.5a.5.5 0 00-.5.5v.5z" /></svg>
         </div>
         <h2 className="text-xl font-black text-white">Active Recall Hub</h2>
         <p className="text-slate-500 mt-2 max-w-xs mx-auto font-medium">Ground your library to generate personalized study decks for neural encoding.</p>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 animate-in fade-in duration-500">
        <div className="relative">
           <div className="w-14 h-14 border-4 border-emerald-500/20 rounded-full"></div>
           <div className="absolute inset-0 w-14 h-14 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
        <div className="text-center space-y-2">
           <p className="text-emerald-400 font-black text-[10px] uppercase tracking-[0.3em] animate-pulse">Encoding Active Recall Cards</p>
           <p className="text-slate-500 text-xs font-medium">Structuring core concepts from syllabus grounded data...</p>
        </div>
      </div>
    );
  }

  if (cards.length === 0) return null;

  const card = cards[currentIdx];

  return (
    <div className="max-w-4xl mx-auto py-12 px-6 flex flex-col items-center space-y-12 animate-in fade-in duration-700">
      <div className="text-center space-y-2">
        <span className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em] block">Syllabus Grounded Deck</span>
        <h2 className="text-3xl font-black text-white tracking-tight">Active Recall Session</h2>
        <p className="text-slate-500 font-bold text-[10px] tracking-widest uppercase py-1 px-3 bg-white/5 border border-white/5 rounded-full inline-block mt-2">
          {weaknesses ? 'Focused Weakness Remediation' : 'Holistic Knowledge Transfer'}
        </p>
      </div>

      <div 
        className="group relative w-full max-w-2xl h-[400px] [perspective:2000px] cursor-pointer"
        onClick={() => setFlipped(!flipped)}
      >
        <div className={`relative w-full h-full transition-all duration-700 [transform-style:preserve-3d] ${flipped ? '[transform:rotateY(180deg)]' : ''}`}>
          {/* Front Face */}
          <div className="absolute inset-0 bg-[#0b0f1a] border border-white/5 rounded-[2.5rem] p-10 md:p-14 flex flex-col items-center justify-center text-center shadow-2xl [backface-visibility:hidden] overflow-hidden group-hover:border-white/20">
            <div className="absolute -top-10 -left-10 w-40 h-40 bg-indigo-500/5 rounded-full blur-3xl"></div>
            <span className="absolute top-10 text-[9px] font-black text-slate-500 uppercase tracking-[0.4em]">Checkpoint Query</span>
            <p className="text-xl md:text-2xl font-black text-white leading-relaxed tracking-tight relative z-10">{card.front}</p>
            <div className="absolute bottom-10 flex items-center space-x-2 text-[10px] font-bold text-slate-600 uppercase tracking-widest bg-white/5 px-4 py-2 rounded-xl">
               <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               <span>Initialize Recall</span>
            </div>
          </div>

          {/* Back Face */}
          <div className="absolute inset-0 bg-indigo-600 border border-indigo-400/30 rounded-[2.5rem] p-10 md:p-14 flex flex-col items-center justify-center text-center shadow-2xl [transform:rotateY(180deg)] [backface-visibility:hidden] overflow-hidden">
            <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-white/10 rounded-full blur-3xl"></div>
            <span className="absolute top-10 text-[9px] font-black text-indigo-200 uppercase tracking-[0.4em]">Ground Truth</span>
            <p className="text-xl md:text-2xl font-black text-white leading-relaxed tracking-tight relative z-10">{card.back}</p>
            <div className="absolute bottom-10 px-4 py-2 bg-black/20 rounded-xl text-[10px] font-bold text-indigo-100 uppercase tracking-widest border border-white/5">
               Neural Encoded
            </div>
          </div>
        </div>
      </div>

      <div className="flex items-center space-x-10 md:space-x-16">
        <button onClick={handlePrev} className="p-5 bg-[#0b0f1a] border border-white/5 rounded-2xl hover:bg-slate-800 text-slate-400 hover:text-white transition-all active:scale-90 shadow-xl" title="Previous Card">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div className="flex flex-col items-center">
           <span className="text-sm font-black text-white tracking-[0.2em]">{currentIdx + 1} / {cards.length}</span>
           <div className="w-12 h-1 bg-white/5 rounded-full mt-2 overflow-hidden">
              <div className="bg-emerald-500 h-full transition-all duration-300" style={{ width: `${((currentIdx + 1) / cards.length) * 100}%` }}></div>
           </div>
        </div>
        <button onClick={handleNext} className="p-5 bg-[#0b0f1a] border border-white/5 rounded-2xl hover:bg-slate-800 text-slate-400 hover:text-white transition-all active:scale-90 shadow-xl" title="Next Card">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>

      <button 
        onClick={loadCards}
        className="px-10 py-4 bg-white/5 border border-white/10 text-slate-400 hover:text-white hover:bg-white/10 rounded-xl font-black text-[10px] uppercase tracking-[0.3em] transition-all active:scale-95"
      >
        Re-Ground Study Deck
      </button>
    </div>
  );
};

