                    { id: AppView.EXAM_MODE, icon: UI_ICONS.Exam, color: 'purple', title: 'Exam Center', desc: 'Custom practice tests generated strictly from your documents.' },
                    { id: AppView.FLASHCARDS, icon: UI_ICONS.Flashcards, color: 'emerald', title: 'Study Cards', desc: 'Neural recall cards focused on your specific weak points.' },
                  ].map((card) => (
                    <div 
                      key={card.id} 
                      onClick={() => documents.length > 0 || card.id === AppView.DOCUMENTS ? setActiveView(card.id) : tryEnterTutoring()}
                      className="group bg-slate-900 p-6 rounded-[1.5rem] border border-slate-800 hover:border-indigo-500/50 hover:bg-slate-800/50 transition-all cursor-pointer shadow-lg"
                    >
                      <div className={`w-10 h-10 bg-${card.color}-500/10 text-${card.color}-400 rounded-lg flex items-center justify-center mb-4`}>{card.icon}</div>
                      <h3 className="text-lg font-black mb-1">{card.title}</h3>
                      <p className="text-slate-500 text-[12px] leading-snug font-medium break-words">{card.desc}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeView === AppView.DOCUMENTS && (
            <PDFManager 
              documents={documents} 
              onUpload={handleUpload} 
              onDelete={handleDeleteDoc}
              onSelect={handleSelectDoc}
              selectedDocId={selectedDocId}
            />
          )}

          {activeView === AppView.TUTORING && selectedDocument && (
            <div className="h-full relative">
              <TutoringView 
                document={selectedDocument} 
                onNavigateToExam={() => setActiveView(AppView.EXAM_MODE)} 
              />
            </div>
          )}

          {activeView === AppView.EXAM_MODE && (
            <ExamMode 
              documents={documents} 
              onNavigateToFlashcards={handleNavigateToFlashcards}
            />
          )}

          {activeView === AppView.FLASHCARDS && (
            <FlashcardsView 
              documents={documents} 
              weaknesses={examWeaknesses} 
            />
          )}

          {activeView === AppView.ANALYTICS && <AnalyticsView />}
          {activeView === AppView.PRICING && <PricingTiers onSelect={handleSelectPlan} />}
        </div>
      </main>
    </div>
  );
};

