import React, { useState } from 'react';
import { PDFDocument } from '../types';
import { analyzePDF } from '../services/geminiService';

interface PDFManagerProps {
  onUpload: (doc: PDFDocument) => void;
  documents: PDFDocument[];
  onDelete: (id: string) => void;
  onSelect: (id: string) => void;
  selectedDocId: string | null;
}

const PDFManager: React.FC<PDFManagerProps> = ({ onUpload, documents, onDelete, onSelect, selectedDocId }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState("");

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setUploadProgress("Analyzing Content...");

    try {
      const result = await analyzePDF(file);

      const newDoc: PDFDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        content: result.fullContent,
        uploadDate: new Date(),
        summary: result.summary,
        topics: result.topics
      };

      onUpload(newDoc);
    } catch (err) {
      console.error("PDF Analysis Failed:", err);
      alert("Analysis failed. Please check your internet connection.");
    } finally {
      setIsUploading(false);
      setUploadProgress("");
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-700">
      <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 p-10 text-center space-y-6 relative overflow-hidden group shadow-xl">
        <div className="space-y-2 max-w-lg mx-auto relative z-10">
          <h2 className="text-2xl md:text-3xl font-black tracking-tight">Intelligence Engine</h2>
          <p className="text-slate-500 text-sm font-medium leading-relaxed">Ground your learning. Upload a PDF to index it into your personalized neural tutoring hub.</p>
        </div>

        {isUploading ? (
          <div className="flex flex-col items-center space-y-3 pt-4">
            <div className="w-8 h-8 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
            <p className="text-indigo-400 font-black text-[10px] uppercase tracking-widest">{uploadProgress}</p>
          </div>
        ) : (
          <label className="relative inline-block px-8 py-3.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-black text-xs uppercase tracking-widest cursor-pointer transition-all active:scale-95 shadow-lg shadow-indigo-600/20">
            Upload Material
            <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} disabled={isUploading} />
