              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center space-x-3 min-w-0 flex-1">
                  <div className={`p-2 rounded-lg ${selectedDocId === doc.id ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                  </div>
                  <div className="min-w-0 flex-1">
                    <h4 className="font-black text-slate-100 truncate text-sm leading-tight" title={doc.name}>{doc.name}</h4>
                    <p className="text-[8px] text-emerald-500 font-bold uppercase tracking-widest mt-0.5">Neural Synced</p>
