import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-12 space-y-6 min-h-[50vh] animate-in fade-in duration-700">
        <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center border border-slate-800">
          <svg className="w-8 h-8 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div className="space-y-1">
          <h2 className="text-xl font-black">Neural Library Empty</h2>
          <p className="text-slate-500 text-sm font-medium">Please ground a PDF before starting an exam session.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-6 min-h-[50vh] animate-in fade-in duration-500">
        <div className="w-12 h-12 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
        <div className="text-center space-y-1">
          <p className="text-indigo-400 font-black text-[10px] uppercase tracking-widest animate-pulse">Synthesizing mastery questions...</p>
        </div>
      </div>
    );
  }

  if (isCompleted) {
    const percentage = Math.round((score / questions.length) * 100);
    return (
      <div className="max-w-xl mx-auto text-center space-y-10 py-10 animate-in zoom-in-95 duration-700">
        <div className="space-y-2">
          <div className="text-6xl font-black text-indigo-500 tracking-tighter leading-none">{percentage}%</div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Neural Mastery Achieved</p>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2rem] shadow-xl text-left space-y-4">
          <h3 className="font-black text-indigo-400 text-[10px] uppercase tracking-widest">Performance Analysis</h3>
          <p className="text-sm text-slate-300 leading-relaxed font-medium break-words">
            {score === questions.length 
              ? "Flawless retention. You have fully indexed this syllabus content in your long-term memory."
              : `Productive checkpoint. You encountered conceptual resistance in ${incorrectTopics.length} specific areas. Khula recommends an active recall session with flashcards.`}
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <button 
            onClick={() => onNavigateToFlashcards(incorrectTopics.join('; '))}
            className="flex-1 py-4 bg-indigo-600 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 shadow-xl shadow-indigo-600/10 active:scale-95 transition-all"
          >
             Ground Flashcards
          </button>
          <button onClick={startExam} className="flex-1 py-4 bg-slate-800 text-slate-300 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-700 active:scale-95 transition-all">New Assessment</button>
        </div>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-3xl mx-auto space-y-6 py-4 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <div className="flex justify-between items-end px-2">
          <div className="space-y-1">
             <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Question {currentIdx + 1} / {questions.length}</span>
             <div className="w-32 h-1 bg-slate-900 rounded-full overflow-hidden">
                <div className="bg-indigo-500 h-full transition-all" style={{ width: `${((currentIdx + 1) / questions.length) * 100}%` }}></div>
             </div>
          </div>
          <span className="text-xs font-bold text-slate-400">Score: {score}</span>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-8 md:p-12 space-y-8 shadow-xl">
          <h3 className="text-xl md:text-2xl font-black leading-tight text-white tracking-tight break-words whitespace-pre-wrap">{q.question}</h3>

          <div className="grid grid-cols-1 gap-3">
            {q.options.map((opt, i) => (
              <button 
                key={i}
                onClick={() => setSelectedAnswer(i)}
                className={`
                  w-full text-left p-5 rounded-xl border transition-all flex items-center space-x-4
                  ${selectedAnswer === i 
                    ? 'bg-indigo-600/10 border-indigo-500 text-white ring-1 ring-indigo-500/20' 
                    : 'bg-slate-950/50 border-slate-800 text-slate-400 hover:border-slate-700 hover:text-slate-200'}
                `}
              >
                <span className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black shrink-0 ${selectedAnswer === i ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'bg-slate-800 border border-slate-700 text-slate-500'}`}>
                  {String.fromCharCode(65 + i)}
                </span>
                <span className="text-sm font-bold leading-snug break-words whitespace-pre-wrap">{opt}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-center pt-2">
          <button 
            disabled={selectedAnswer === null}
            onClick={handleNext}
            className={`px-12 py-4 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${selectedAnswer !== null ? 'bg-indigo-600 text-white hover:bg-indigo-500 shadow-xl shadow-indigo-600/10 active:scale-95' : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-slate-800'}`}
          >
            {currentIdx === questions.length - 1 ? 'Finish Exam' : 'Next Checkpoint'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center space-y-8 min-h-[50vh] text-center max-w-lg mx-auto py-10 animate-in fade-in duration-700">
      <div className="p-6 bg-indigo-600/10 rounded-[1.5rem] border border-indigo-500/20 shadow-xl shadow-indigo-600/5">
         <svg className="w-12 h-12 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
      </div>
      <div className="space-y-3">
        <h2 className="text-3xl font-black tracking-tight">Mastery Checkpoint</h2>
        <p className="text-slate-500 text-sm font-medium leading-relaxed">Quantify your progress. Generate a practice assessment based strictly on your uploaded materials.</p>
      </div>
      <button 
        onClick={startExam}
        className="px-10 py-4 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 shadow-xl shadow-indigo-600/10 active:scale-95 transition-all"
      >
        Synthesize Exam
      </button>
    </div>
  );
};

export default ExamMode;

import React, { useState, useEffect } from 'react';
import { PDFDocument, FlashCard } from '../types';
import { generateFlashcards } from '../services/geminiService';

interface FlashcardsViewProps {
  documents: PDFDocument[];
  weaknesses?: string;
}

const FlashcardsView: React.FC<FlashcardsViewProps> = ({ documents, weaknesses = "" }) => {
  const [cards, setCards] = useState<FlashCard[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (documents.length > 0) {
      loadCards();
    }
  }, [documents]);

  const loadCards = async () => {
    setIsLoading(true);
    try {
      const context = documents.map(d => d.content).join('\n');
      const generated = await generateFlashcards(context, weaknesses);
      setCards(generated);
      setCurrentIdx(0);
      setFlipped(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleNext = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev + 1) % cards.length);
    }, 150);
  };

  const handlePrev = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev - 1 + cards.length) % cards.length);
    }, 150);
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] text-center p-12 animate-in fade-in duration-700">
         <div className="p-6 bg-slate-900 rounded-2xl border border-slate-800 mb-6 text-slate-700">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2" /></svg>
         </div>
         <h2 className="text-xl font-black">Active Recall Engine</h2>
         <p className="text-slate-500 mt-2 max-w-xs mx-auto text-sm font-medium leading-relaxed">Ground your library to generate personalized recall cards.</p>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] space-y-6 animate-in fade-in duration-500">
        <div className="w-10 h-10 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
        <div className="text-center space-y-1">
           <p className="text-emerald-400 font-black text-[10px] uppercase tracking-widest animate-pulse">Encoding Study Cards...</p>
        </div>
      </div>
    );
  }

  if (cards.length === 0) return null;

  const card = cards[currentIdx];

  return (
    <div className="max-w-4xl mx-auto py-8 px-4 flex flex-col items-center space-y-10 animate-in fade-in duration-700">
      <div className="text-center space-y-1">
        <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest block">Syllabus Grounded Session</span>
        <h2 className="text-2xl font-black tracking-tight">Neural Encoding Cards</h2>
        {weaknesses && (
           <p className="text-slate-500 font-bold text-[9px] tracking-widest uppercase py-1 px-3 bg-slate-800 rounded-full inline-block mt-2 border border-slate-700">Weakness Targeted</p>
        )}
      </div>

      <div 
        className="group relative w-full max-w-xl h-[340px] [perspective:1000px] cursor-pointer"
        onClick={() => setFlipped(!flipped)}
      >
        <div className={`relative w-full h-full transition-all duration-500 [transform-style:preserve-3d] ${flipped ? '[transform:rotateY(180deg)]' : ''}`}>
          {/* Front Face */}
          <div className="absolute inset-0 bg-slate-900 border border-slate-800 rounded-[2rem] p-8 md:p-12 flex flex-col items-center justify-center text-center shadow-xl [backface-visibility:hidden] overflow-y-auto chat-scroll">
            <span className="absolute top-6 text-[9px] font-black text-slate-500 uppercase tracking-widest">Question</span>
            <p className="text-lg md:text-xl font-black text-white leading-relaxed tracking-tight break-words whitespace-pre-wrap">{card.front}</p>
            <div className="absolute bottom-6 flex items-center space-x-2 text-[10px] font-bold text-slate-600 uppercase tracking-widest">
               <span>Tap to Reveal</span>
            </div>
          </div>

          {/* Back Face */}
          <div className="absolute inset-0 bg-indigo-600 border border-indigo-400/30 rounded-[2rem] p-8 md:p-12 flex flex-col items-center justify-center text-center shadow-xl [transform:rotateY(180deg)] [backface-visibility:hidden] overflow-y-auto chat-scroll">
            <span className="absolute top-6 text-[9px] font-black text-indigo-200 uppercase tracking-widest">Answer</span>
            <p className="text-lg md:text-xl font-black text-white leading-relaxed tracking-tight break-words whitespace-pre-wrap">{card.back}</p>
            <div className="absolute bottom-6 px-3 py-1 bg-black/10 rounded-lg text-[9px] font-bold text-indigo-100 uppercase tracking-widest">Neural Locked</div>
          </div>
        </div>
      </div>

      <div className="flex items-center space-x-12">
        <button onClick={handlePrev} className="p-4 bg-slate-900 border border-slate-800 rounded-xl hover:bg-slate-800 text-slate-400 hover:text-white transition-all active:scale-90 shadow-lg" title="Previous">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
        </button>
        <span className="text-xs font-black text-white tracking-widest">{currentIdx + 1} / {cards.length}</span>
        <button onClick={handleNext} className="p-4 bg-slate-900 border border-slate-800 rounded-xl hover:bg-slate-800 text-slate-400 hover:text-white transition-all active:scale-90 shadow-lg" title="Next">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>

      <button 
        onClick={loadCards}
        className="px-8 py-3 bg-slate-800/50 border border-slate-800 text-slate-500 hover:text-white hover:bg-slate-800 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95"
      >
        Refresh Deck
      </button>
    </div>
  );
};

export default FlashcardsView;

