import React, { useState } from 'react';
import { PDFDocument } from '../types';
import { analyzePDF } from '../services/geminiService';

interface PDFManagerProps {
  onUpload: (doc: PDFDocument) => void;
  documents: PDFDocument[];
  onDelete: (id: string) => void;
  onSelect: (id: string) => void;
  selectedDocId: string | null;
}

const PDFManager: React.FC<PDFManagerProps> = ({ onUpload, documents, onDelete, onSelect, selectedDocId }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState("");

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setUploadProgress("Analyzing Content...");

    try {
      const result = await analyzePDF(file);

      const newDoc: PDFDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        content: result.fullContent,
        uploadDate: new Date(),
        summary: result.summary,
        topics: result.topics
      };

      onUpload(newDoc);
    } catch (err) {
      console.error("PDF Analysis Failed:", err);
      alert("Analysis failed. Please check your internet connection.");
    } finally {
      setIsUploading(false);
      setUploadProgress("");
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-700">
      <div className="bg-slate-900 rounded-[2rem] border border-slate-800 p-10 text-center space-y-6 relative overflow-hidden shadow-xl">
        <div className="space-y-2 max-w-lg mx-auto">
          <h2 className="text-3xl font-black tracking-tight text-white">Knowledge Hub</h2>
          <p className="text-slate-500 text-sm font-medium leading-relaxed">Upload academic materials to ground your AI Tutor in your specific curriculum.</p>
        </div>

        {isUploading ? (
          <div className="flex flex-col items-center space-y-3 pt-4">
            <div className="w-8 h-8 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
            <p className="text-indigo-400 font-black text-[10px] uppercase tracking-widest">{uploadProgress}</p>
          </div>
        ) : (
          <label className="relative inline-block px-8 py-3.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-black text-xs uppercase tracking-widest cursor-pointer transition-all active:scale-95 shadow-lg shadow-indigo-600/20">
            Upload PDF Material
            <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} disabled={isUploading} />
          </label>
        )}
      </div>

      <div className="space-y-4">
        <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-2">Your Grounded Library</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-10">
          {documents.length === 0 && !isUploading && (
            <div className="col-span-full py-16 text-center border-2 border-dashed border-slate-800 rounded-[2rem] opacity-30">
              <p className="text-xs font-bold uppercase tracking-widest">No Materials Linked Yet</p>
            </div>
          )}
          {documents.map(doc => (
            <div key={doc.id} className={`bg-slate-900 border ${selectedDocId === doc.id ? 'border-indigo-500' : 'border-slate-800'} rounded-[1.5rem] p-6 flex flex-col group transition-all shadow-md overflow-hidden`}>
              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center space-x-3 min-w-0 flex-1">
                  <div className={`p-2 rounded-lg shrink-0 ${selectedDocId === doc.id ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                  </div>
                  <div className="min-w-0 flex-1">
                    <h4 className="font-black text-slate-100 truncate text-sm leading-tight break-words" title={doc.name}>{doc.name}</h4>
                    <p className="text-[8px] text-emerald-500 font-bold uppercase tracking-widest mt-0.5">Neural Synced</p>
                  </div>
                </div>
                <button onClick={() => onDelete(doc.id)} className="p-1.5 text-slate-700 hover:text-red-500 transition-colors ml-2 shrink-0">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <div className="flex-1 space-y-3 overflow-hidden">
                 <p className="text-[11px] text-slate-400 font-medium leading-relaxed break-words line-clamp-3 h-12">
                   {doc.summary}
                 </p>
                 <div className="flex flex-wrap gap-1">
                    {doc.topics?.slice(0, 3).map(t => (
                      <span key={t} className="px-2 py-0.5 bg-slate-800 text-slate-500 text-[8px] font-bold rounded border border-slate-700/50 uppercase tracking-tighter truncate max-w-full">{t}</span>
                    ))}
                 </div>
              </div>

              <button 
                onClick={() => onSelect(doc.id)}
                className={`w-full mt-5 py-3 rounded-xl font-black text-[10px] uppercase tracking-[0.1em] transition-all
                  ${selectedDocId === doc.id ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-800 text-slate-400 hover:text-white'}
                `}
              >
                {selectedDocId === doc.id ? 'Context Active' : 'Start Session'}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default PDFManager;

import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-12 space-y-6 min-h-[50vh] animate-in fade-in duration-700">
        <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center border border-slate-800 shadow-lg">
          <svg className="w-8 h-8 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div className="space-y-1">
          <h2 className="text-xl font-black text-white">Neural Hub Empty</h2>
          <p className="text-slate-500 text-sm font-medium">Please ground a PDF before starting an assessment.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-6 min-h-[50vh] animate-in fade-in duration-500">
        <div className="w-12 h-12 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
        <div className="text-center space-y-1">
          <p className="text-indigo-400 font-black text-[10px] uppercase tracking-widest animate-pulse">Synthesizing Mastery Data...</p>
        </div>
      </div>
    );
  }

  if (isCompleted) {
    const percentage = Math.round((score / questions.length) * 100);
    return (
      <div className="max-w-xl mx-auto text-center space-y-10 py-10 animate-in zoom-in-95 duration-700">
        <div className="space-y-2">
          <div className="text-7xl font-black text-indigo-500 tracking-tighter leading-none drop-shadow-lg">{percentage}%</div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px]">Proficiency Level Achieved</p>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-8 rounded-[2rem] shadow-2xl text-left space-y-4">
          <h3 className="font-black text-indigo-400 text-[10px] uppercase tracking-widest">Mastery Report</h3>
          <p className="text-sm text-slate-300 leading-relaxed font-medium break-words">
            {score === questions.length 
              ? "Exceptional retention. You have successfully mapped every conceptual authority from your materials."
              : `Productive diagnostic. You encountered conceptual resistance in ${incorrectTopics.length} areas. Khula recommends targeting these through active recall.`}
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4">
          <button 
            onClick={() => onNavigateToFlashcards(incorrectTopics.join('; '))}
            className="flex-1 py-4 bg-indigo-600 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 shadow-xl shadow-indigo-600/10 active:scale-95 transition-all"
          >
             Review Weak Points
          </button>
          <button onClick={startExam} className="flex-1 py-4 bg-slate-800 text-slate-300 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-700 active:scale-95 transition-all">Retry Diagnostic</button>
        </div>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-3xl mx-auto space-y-6 py-4 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <div className="flex justify-between items-end px-2">
          <div className="space-y-1">
             <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Question {currentIdx + 1} of {questions.length}</span>
             <div className="w-40 h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className="bg-indigo-500 h-full transition-all duration-500" style={{ width: `${((currentIdx + 1) / questions.length) * 100}%` }}></div>
             </div>
          </div>
          <span className="text-xs font-bold text-slate-400">Score Tracker: {score}</span>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-8 md:p-12 space-y-10 shadow-2xl overflow-hidden">
          <h3 className="text-xl md:text-2xl font-black leading-tight text-white tracking-tight break-words whitespace-pre-wrap">
            {q.question}
          </h3>

          <div className="grid grid-cols-1 gap-3">
            {q.options.map((opt, i) => (
              <button 
                key={i}
                onClick={() => setSelectedAnswer(i)}
                className={`
                  w-full text-left p-5 rounded-xl border transition-all flex items-center space-x-4
                  ${selectedAnswer === i 
                    ? 'bg-indigo-600/10 border-indigo-500 text-white shadow-inner' 
                    : 'bg-slate-950/50 border-slate-800 text-slate-400 hover:border-slate-600 hover:text-slate-200'}
                `}
              >
                <span className={`w-8 h-8 rounded-lg flex items-center justify-center text-[10px] font-black shrink-0 ${selectedAnswer === i ? 'bg-indigo-600 text-white' : 'bg-slate-800 border border-slate-700'}`}>
                  {String.fromCharCode(65 + i)}
                </span>
                <span className="text-sm font-bold leading-snug break-words whitespace-pre-wrap flex-1">{opt}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-center pt-2">
          <button 
            disabled={selectedAnswer === null}
            onClick={handleNext}
            className={`px-14 py-4 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${selectedAnswer !== null ? 'bg-indigo-600 text-white hover:bg-indigo-500 shadow-xl shadow-indigo-600/10 active:scale-95' : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-slate-800'}`}
          >
            {currentIdx === questions.length - 1 ? 'Analyze Final Score' : 'Continue Diagnostic'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center space-y-8 min-h-[50vh] text-center max-w-lg mx-auto py-10 animate-in fade-in duration-700">
      <div className="p-6 bg-indigo-600/10 rounded-2xl border border-indigo-500/20 shadow-xl">
         <svg className="w-12 h-12 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
      </div>
      <div className="space-y-3">
        <h2 className="text-3xl font-black tracking-tight text-white">Academic Diagnostic</h2>
        <p className="text-slate-500 text-sm font-medium leading-relaxed">Quantify your retention levels. Generate a practice assessment grounded in your unique learning context.</p>
      </div>
      <button 
        onClick={startExam}
        className="px-12 py-4 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 shadow-xl shadow-indigo-600/10 active:scale-95 transition-all"
      >
        Synthesize Assessment
      </button>
    </div>
  );
};

