        <aside className="w-64 bg-slate-900 border-r border-slate-800 flex flex-col z-30 shadow-2xl shrink-0">
          <div className="p-6">
            <div className="flex items-center space-x-3 mb-1">
              <div className="bg-indigo-600 w-8 h-8 flex items-center justify-center rounded-lg text-white font-black shadow-lg">K</div>
              <h1 className="text-xl font-black tracking-tight">Khula Tutor</h1>
            </div>
            <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest pl-1">Intelligent Academia</p>
          </div>

          <nav className="flex-1 px-3 space-y-1.5 overflow-y-auto chat-scroll pt-2">
            {navItems.map(item => {
              const isDisabled = item.requiresDoc && documents.length === 0;
              const isActive = activeView === item.id;
              return (
                <button
                  key={item.id}
                  onClick={() => isDisabled ? tryEnterTutoring() : setActiveView(item.id)}
                  className={`
                    w-full flex items-center space-x-3 px-3.5 py-3 rounded-xl text-sm font-semibold transition-all group
                    ${isActive 
                      ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20' 
                      : isDisabled 
                        ? 'text-slate-600 cursor-not-allowed opacity-40'
                        : 'text-slate-400 hover:bg-slate-800 hover:text-white'}
                  `}
                >
                  <span className={`${isActive ? 'text-white' : 'text-slate-500 group-hover:text-indigo-400'} transition-colors`}>
                    {item.icon}
                  </span>
                  <span className="truncate">{item.label}</span>
                </button>
              );
            })}
          </nav>

          <div className="p-5 bg-slate-800/40 m-4 rounded-2xl border border-slate-700/50">
             <div className="flex items-center justify-between mb-2.5 px-1">
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-wider">Sync State</span>
               <span className="text-[10px] font-bold text-indigo-400">{documents.length}/10 Grounded</span>
             </div>
             <div className="w-full bg-slate-950 h-1.5 rounded-full overflow-hidden">
