            </div>
            <div className="flex items-center space-x-6">
               <div className="hidden md:flex flex-col items-end">
                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Academic Status</span>
                  <span className="text-xs font-bold text-emerald-400">Secure & Online</span>
               </div>
               <div className="w-10 h-10 rounded-xl bg-slate-800 border border-slate-700 flex items-center justify-center text-slate-400 hover:text-white transition-colors cursor-help">
                  <span className="text-xs font-black">{subscription[0]}</span>
               </div>
            </div>
          </header>
        )}

        <div className={`flex-1 overflow-y-auto chat-scroll ${isImmersive ? "" : "p-10"}`}>
          {activeView === AppView.DASHBOARD && (
            <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in duration-700">
               <div className="bg-indigo-600 rounded-[2.5rem] p-10 md:p-14 text-white shadow-[0_30px_60px_-15px_rgba(79,70,229,0.3)] relative overflow-hidden">
                  <div className="relative z-10 space-y-6">
                    <div className="inline-block px-3 py-1 bg-white/10 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] border border-white/10">Welcome back, Scholar</div>
                    <h2 className="text-4xl md:text-5xl font-black leading-tight tracking-tight">Your Personal <br/><span className="text-indigo-200">Syllabus-Grounded AI.</span></h2>
                    <p className="text-indigo-100 text-sm md:text-lg max-w-2xl font-medium opacity-90 leading-relaxed">
                      Stop generic AI hallucinations. Khula indexes your specific textbooks and notes, creating a unique neural partner that knows your curriculum as well as you do.
                    </p>
                    <div className="flex flex-wrap items-center gap-4 pt-4">
                      <button 
                        onClick={() => setActiveView(AppView.DOCUMENTS)}
                        className="px-8 py-4 bg-white text-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all active:scale-95 shadow-xl shadow-black/10"
                      >
