                    </div>
                  </div>
                  <div className="absolute -right-20 top-0 bottom-0 w-1/2 bg-white/5 skew-x-12 transform translate-x-1/2 pointer-events-none"></div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  {[
                    { id: AppView.DOCUMENTS, icon: UI_ICONS.Documents, color: 'indigo', title: 'Knowledge Hub', desc: 'Securely upload syllabus PDFs. Our engine extracts and structures every core concept.' },
                    { id: AppView.EXAM_MODE, icon: UI_ICONS.Exam, color: 'purple', title: 'Exam Center', desc: 'Synthesize practice assessments based strictly on facts found in your grounded materials.' },
                    { id: AppView.FLASHCARDS, icon: UI_ICONS.Flashcards, color: 'emerald', title: 'Memory Lab', desc: 'Deploy neural recall techniques to lock in topics identified as academic weak points.' },
                  ].map((card) => (
                    <div 
                      key={card.id} 
                      onClick={() => documents.length > 0 || card.id === AppView.DOCUMENTS ? setActiveView(card.id) : tryEnterTutoring()}
                      className="group bg-slate-900 p-8 rounded-[2rem] border border-slate-800 hover:border-indigo-500/50 hover:bg-slate-800/60 transition-all cursor-pointer shadow-xl flex flex-col min-h-[220px]"
                    >
                      <div className={`w-12 h-12 bg-${card.color}-500/10 text-${card.color}-400 rounded-xl flex items-center justify-center mb-6 transition-transform group-hover:scale-110`}>{card.icon}</div>
                      <h3 className="text-xl font-black mb-3 text-white">{card.title}</h3>
                      <p className="text-slate-500 text-[13px] leading-relaxed font-medium break-words overflow-hidden">{card.desc}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeView === AppView.DOCUMENTS && (
            <PDFManager 
              documents={documents} 
              onUpload={handleUpload} 
              onDelete={handleDeleteDoc}
              onSelect={handleSelectDoc}
              selectedDocId={selectedDocId}
            />
          )}

          {activeView === AppView.TUTORING && selectedDocument && (
            <div className="h-full relative animate-in fade-in duration-500">
              <TutoringView 
                document={selectedDocument} 
                onNavigateToExam={() => setActiveView(AppView.EXAM_MODE)} 
              />
            </div>
          )}

          {activeView === AppView.EXAM_MODE && (
            <ExamMode 
              documents={documents} 
              onNavigateToFlashcards={handleNavigateToFlashcards}
            />
          )}

          {activeView === AppView.FLASHCARDS && (
            <FlashcardsView 
              documents={documents} 
              weaknesses={examWeaknesses} 
            />
          )}

          {activeView === AppView.ANALYTICS && <AnalyticsView />}
          {activeView === AppView.PRICING && <PricingTiers onSelect={handleSelectPlan} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { PDFDocument } from '../types';
import { analyzePDF } from '../services/geminiService';

interface PDFManagerProps {
  onUpload: (doc: PDFDocument) => void;
  documents: PDFDocument[];
  onDelete: (id: string) => void;
  onSelect: (id: string) => void;
  selectedDocId: string | null;
}

const PDFManager: React.FC<PDFManagerProps> = ({ onUpload, documents, onDelete, onSelect, selectedDocId }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState("");

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setUploadProgress("Analyzing Content...");

    try {
      const result = await analyzePDF(file);

      const newDoc: PDFDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        content: result.fullContent,
        uploadDate: new Date(),
        summary: result.summary,
        topics: result.topics
      };

      onUpload(newDoc);
    } catch (err) {
      console.error("PDF Analysis Failed:", err);
      alert("Analysis failed. Please verify the document format.");
    } finally {
      setIsUploading(false);
      setUploadProgress("");
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in duration-700">
      <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 p-12 text-center space-y-8 relative overflow-hidden group shadow-2xl">
        <div className="absolute inset-0 bg-indigo-500/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="space-y-4 max-w-xl mx-auto relative z-10">
          <h2 className="text-3xl font-black tracking-tight text-white">Academic Knowledge Input</h2>
          <p className="text-slate-500 text-base font-medium leading-relaxed">Index your study materials to initialize the grounding phase of the AI Tutor.</p>
        </div>

        {isUploading ? (
          <div className="flex flex-col items-center space-y-4 pt-4">
            <div className="w-10 h-10 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
