import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-12 space-y-8 min-h-[60vh] animate-in fade-in duration-700">
        <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center border border-slate-800 shadow-2xl">
          <svg className="w-10 h-10 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div className="space-y-3">
          <h2 className="text-2xl font-black text-white">Neural Hub Empty</h2>
          <p className="text-slate-500 text-sm font-medium max-w-sm mx-auto leading-relaxed">Please ground your academic materials in the Knowledge Hub before initiating an assessment session.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-8 min-h-[60vh] animate-in fade-in duration-500">
        <div className="relative">
          <div className="w-16 h-16 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
          <div className="absolute inset-0 w-16 h-16 blur-xl bg-indigo-500/10 rounded-full"></div>
        </div>
        <div className="text-center space-y-2">
          <p className="text-indigo-400 font-black text-[11px] uppercase tracking-[0.3em] animate-pulse">Synthesizing Course Data...</p>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Grounding Mastery Assessment</p>
        </div>
      </div>
    );
  }

  if (isCompleted) {
    const percentage = Math.round((score / questions.length) * 100);
    return (
      <div className="max-w-2xl mx-auto text-center space-y-12 py-10 animate-in zoom-in-95 duration-700">
        <div className="space-y-4">
          <div className="text-8xl font-black text-indigo-500 tracking-tighter leading-none drop-shadow-2xl">{percentage}%</div>
          <p className="text-slate-500 font-black uppercase tracking-[0.4em] text-[12px]">Assessment Efficiency Achieved</p>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-10 rounded-[2.5rem] shadow-2xl text-left space-y-5 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-500/5 -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
          <h3 className="font-black text-indigo-400 text-[11px] uppercase tracking-[0.3em]">Mastery Feedback</h3>
          <p className="text-[15px] text-slate-300 leading-relaxed font-medium break-words">
            {score === questions.length 
              ? "Flawless academic retention. Your neural map of this material is 100% complete and grounded in accuracy."
