                    ? 'bg-indigo-600/10 border-indigo-500 text-white shadow-xl ring-1 ring-indigo-500/20' 
                    : 'bg-slate-950/50 border-slate-800 text-slate-400 hover:border-slate-600 hover:text-slate-100'}
                `}
              >
                <span className={`w-10 h-10 rounded-xl flex items-center justify-center text-[11px] font-black shrink-0 transition-all ${selectedAnswer === i ? 'bg-indigo-600 text-white scale-110 shadow-lg' : 'bg-slate-800 border border-slate-700 text-slate-500'}`}>
                  {String.fromCharCode(65 + i)}
                </span>
                <span className="text-base font-bold leading-relaxed break-words whitespace-pre-wrap flex-1">{opt}</span>
                {selectedAnswer === i && (
                  <div className="absolute right-6 top-1/2 -translate-y-1/2">
