        )}

        {!isImmersive && (
          <header className="h-24 px-10 flex items-center justify-between sticky top-0 bg-slate-950/60 backdrop-blur-xl z-20 border-b border-slate-900/50">
            <div className="flex flex-col">
               <h2 className="text-2xl font-black capitalize tracking-tight">{activeView.replace('_', ' ')}</h2>
               <p className="text-xs text-slate-500 font-medium">Personalized Digital Tutoring Environment</p>
            </div>
            <div className="flex items-center space-x-4 bg-slate-900/50 rounded-2xl p-2.5 pr-6 border border-slate-800">
               <div className="w-10 h-10 rounded-xl bg-gradient-to-tr from-indigo-600 to-purple-500"></div>
               <div className="flex flex-col">
                  <span className="text-sm font-black">Student Scholar</span>
                  <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">Academic Level 12</span>
               </div>
            </div>
          </header>
        )}

        <div className={isImmersive ? "" : "p-10"}>
          {activeView === AppView.DASHBOARD && (
            <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
               <div className="relative overflow-hidden bg-indigo-600 rounded-[2.5rem] p-12 text-white shadow-2xl shadow-indigo-600/30">
                  <div className="relative z-10 max-w-2xl space-y-4">
                    <h2 className="text-5xl font-black leading-tight break-words">Ready to Master Your Syllabus?</h2>
                    <p className="text-indigo-100 text-lg font-medium opacity-90 leading-relaxed break-words">
                      {documents.length > 0 
                        ? `You have ${documents.length} materials ready. Select one to start your conversation.`
                        : "Start by uploading your materials in the Intelligence Hub to activate your AI Tutor."}
                    </p>
                    <button 
                      onClick={() => setActiveView(AppView.DOCUMENTS)}
                      className="mt-4 px-10 py-4 bg-white text-indigo-600 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-slate-100 transition-all shadow-xl shadow-black/10"
                    >
                      {documents.length > 0 ? 'View Library' : 'Upload Material'}
                    </button>
                  </div>
                  <div className="absolute -right-20 -bottom-20 w-96 h-96 bg-white/10 rounded-full blur-3xl"></div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  {[
                    { 
                      view: AppView.DOCUMENTS, 
                      icon: UI_ICONS.Documents, 
                      color: 'indigo', 
                      title: 'Intelligence Hub', 
                      desc: 'Ground your tutor in your personal notes, research papers, or textbooks with seamless extraction.' 
                    },
                    { 
                      view: AppView.EXAM_MODE, 
                      icon: UI_ICONS.Exam, 
                      color: 'purple', 
                      title: 'Exam Mode', 
                      desc: 'Simulate high-pressure exam conditions using questions derived strictly from your grounded materials.' 
                    },
                    { 
                      view: AppView.FLASHCARDS, 
                      icon: UI_ICONS.Flashcards, 
                      color: 'blue', 
                      title: 'Flashcards', 
                      desc: 'Deploy active recall techniques with study cards tailored specifically to identified weak concepts.' 
                    }
                  ].map((card, i) => {
                    const isDisabled = documents.length === 0 && card.view !== AppView.DOCUMENTS;
                    return (
                      <div 
                        key={i}
                        className={`bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 flex flex-col transition-all cursor-pointer shadow-xl min-h-[300px] ${isDisabled ? 'opacity-50 grayscale' : `hover:border-${card.color}-500/50 hover:bg-slate-800/40`}`}
                        onClick={() => !isDisabled ? setActiveView(card.view) : tryEnterTutoring()}
                      >
                        <div className={`w-14 h-14 bg-${card.color}-500/10 text-${card.color}-400 rounded-2xl flex items-center justify-center mb-8 shrink-0`}>
                          {card.icon}
                        </div>
                        <h3 className="text-2xl font-black mb-4 break-words">{card.title}</h3>
                        <p className="text-slate-400 text-sm leading-relaxed mb-6 break-words flex-grow">{card.desc}</p>
                      </div>
                    );
                  })}
               </div>
            </div>
          )}

          {activeView === AppView.DOCUMENTS && (
            <PDFManager 
              documents={documents} 
              onUpload={handleUpload} 
              onDelete={handleDeleteDoc}
              onSelect={handleSelectDoc}
              selectedDocId={selectedDocId}
            />
          )}

          {activeView === AppView.TUTORING && selectedDocument && (
            <div className="animate-in zoom-in-95 duration-500 h-full">
              <button 
                onClick={() => setActiveView(AppView.DASHBOARD)}
                className="absolute top-8 left-8 z-50 p-4 bg-slate-900/50 hover:bg-slate-800 border border-slate-800 rounded-2xl text-slate-400 transition-all"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <TutoringView 
                document={selectedDocument} 
                onNavigateToExam={() => setActiveView(AppView.EXAM_MODE)} 
              />
            </div>
          )}

          {activeView === AppView.EXAM_MODE && (
            <ExamMode 
              documents={documents} 
              onNavigateToFlashcards={handleNavigateToFlashcards}
            />
          )}

          {activeView === AppView.FLASHCARDS && (
            <FlashcardsView 
              documents={documents} 
              weaknesses={examWeaknesses} 
            />
          )}

          {activeView === AppView.ANALYTICS && <AnalyticsView />}
          {activeView === AppView.PRICING && <PricingTiers onSelect={handleSelectPlan} />}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { PDFDocument } from '../types';
import { analyzePDF } from '../services/geminiService';

interface PDFManagerProps {
  onUpload: (doc: PDFDocument) => void;
  documents: PDFDocument[];
  onDelete: (id: string) => void;
  onSelect: (id: string) => void;
  selectedDocId: string | null;
}

const PDFManager: React.FC<PDFManagerProps> = ({ onUpload, documents, onDelete, onSelect, selectedDocId }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState("");

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setUploadProgress("Analyzing Material via Intelligence Engine...");

    try {
      const result = await analyzePDF(file);

      const newDoc: PDFDocument = {
        id: Math.random().toString(36).substr(2, 9),
        name: file.name,
        content: result.fullContent,
        uploadDate: new Date(),
        summary: result.summary,
        topics: result.topics
      };

      onUpload(newDoc);
    } catch (err) {
      console.error("PDF Analysis Failed:", err);
      alert("Failed to analyze the academic material. Please try a different PDF.");
    } finally {
      setIsUploading(false);
      setUploadProgress("");
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-12 py-6 animate-in fade-in duration-700">
      <div className="bg-slate-900 rounded-[3rem] border border-slate-800 p-16 text-center space-y-8 relative overflow-hidden group shadow-2xl">
        <div className="absolute inset-0 bg-indigo-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="relative inline-flex p-6 bg-indigo-500/10 rounded-3xl border border-indigo-500/20 group-hover:scale-110 transition-transform">
          <svg className="w-10 h-10 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
        </div>
        <div className="space-y-4 max-w-2xl mx-auto">
          <h2 className="text-4xl font-black tracking-tight break-words">Intelligence Hub</h2>
          <p className="text-slate-400 text-lg leading-relaxed font-medium break-words">Upload your academic materials. Khula's Engine will extract, structure, and index every concept for your personalized session.</p>
        </div>

        {isUploading ? (
          <div className="flex flex-col items-center space-y-4">
            <div className="flex space-x-2">
              <div className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              <div className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce"></div>
            </div>
            <p className="text-indigo-400 font-black text-xs uppercase tracking-widest">{uploadProgress}</p>
          </div>
        ) : (
          <label className="relative inline-block px-12 py-5 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-black text-sm uppercase tracking-widest cursor-pointer transition-all active:scale-95 shadow-xl shadow-indigo-600/20">
            Upload Study Material
            <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} disabled={isUploading} />
          </label>
        )}
      </div>

      <div className="space-y-6">
        <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.3em] ml-4">Grounded Knowledge Library</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {documents.length === 0 && !isUploading && (
            <div className="col-span-full py-24 text-center border-2 border-dashed border-slate-800 rounded-[3rem] opacity-30">
              <p className="text-sm font-bold uppercase tracking-widest">Library Empty - Awaiting Academic Context</p>
            </div>
          )}
          {documents.map(doc => (
            <div key={doc.id} className={`bg-slate-900 border ${selectedDocId === doc.id ? 'border-indigo-500 ring-2 ring-indigo-500/20 shadow-indigo-500/10' : 'border-slate-800'} rounded-[2.5rem] p-8 flex flex-col transition-all hover:border-slate-600 shadow-xl min-h-[380px] overflow-hidden`}>
              <div className="flex items-start justify-between mb-8 shrink-0">
                <div className="flex items-center space-x-5 min-w-0 flex-1">
                  <div className={`p-4 bg-slate-950 rounded-2xl text-slate-400 transition-colors shrink-0 ${selectedDocId === doc.id ? 'text-indigo-500 bg-indigo-500/5' : ''}`}>
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                  </div>
                  <div className="min-w-0 flex-1">
                    <h4 className="font-black text-slate-100 text-lg leading-tight break-words line-clamp-2" title={doc.name}>{doc.name}</h4>
                    <p className="text-[10px] text-emerald-500 font-bold uppercase tracking-wider mt-1">Neural Analyzed</p>
                  </div>
                </div>
                <button onClick={() => onDelete(doc.id)} className="p-2 text-slate-700 hover:text-red-500 rounded-xl transition-colors shrink-0 ml-2">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
              </div>

              <div className="flex-grow space-y-4 overflow-hidden mb-8">
                 <p className="text-[13px] text-slate-400 font-medium leading-relaxed break-words line-clamp-4 min-h-[4rem]">{doc.summary}</p>
                 <div className="flex flex-wrap gap-2 pt-2">
                    {doc.topics?.slice(0, 4).map(t => (
                      <span key={t} className="px-2.5 py-1 bg-slate-800 text-slate-400 text-[10px] font-bold rounded-lg border border-slate-700/50 uppercase tracking-tighter truncate max-w-full">{t}</span>
                    ))}
                 </div>
              </div>

              <button 
                onClick={() => onSelect(doc.id)}
                className={`w-full py-5 rounded-2xl font-black text-[12px] uppercase tracking-[0.2em] transition-all shrink-0
                  ${selectedDocId === doc.id ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/20' : 'bg-slate-800 text-slate-300 hover:bg-slate-700'}
                `}
              >
                {selectedDocId === doc.id ? 'Sync Active - Enter Room' : 'Deploy Session'}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default PDFManager;

import React, { useState } from 'react';
import { PDFDocument, QuizQuestion } from '../types';
import { generateQuiz } from '../services/geminiService';

interface ExamModeProps {
  documents: PDFDocument[];
  onNavigateToFlashcards: (weaknesses: string) => void;
}

const ExamMode: React.FC<ExamModeProps> = ({ documents, onNavigateToFlashcards }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [score, setScore] = useState(0);
  const [isCompleted, setIsCompleted] = useState(false);
  const [incorrectTopics, setIncorrectTopics] = useState<string[]>([]);

  const startExam = async () => {
    if (documents.length === 0) return;
    setIsGenerating(true);
    setIncorrectTopics([]);
    try {
      const context = documents.map(d => d.content).join('\n');
      const quiz = await generateQuiz(context);
      setQuestions(quiz);
      setCurrentIdx(0);
      setScore(0);
      setIsCompleted(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNext = () => {
    const q = questions[currentIdx];
    if (selectedAnswer === q.correctAnswer) {
      setScore(s => s + 1);
    } else {
      setIncorrectTopics(prev => [...prev, q.question]);
    }

    if (currentIdx < questions.length - 1) {
      setCurrentIdx(i => i + 1);
      setSelectedAnswer(null);
    } else {
      setIsCompleted(true);
    }
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-12 space-y-8 min-h-[60vh] animate-in fade-in duration-700">
        <div className="w-24 h-24 bg-slate-900 rounded-[2.5rem] flex items-center justify-center border border-slate-800 shadow-2xl">
          <svg className="w-12 h-12 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
        </div>
        <div className="space-y-3">
          <h2 className="text-3xl font-black text-white tracking-tight">Intelligence Hub Empty</h2>
          <p className="text-slate-500 text-base font-medium max-w-sm mx-auto leading-relaxed">Upload academic context to ground your AI Tutor before starting an assessment.</p>
        </div>
      </div>
    );
  }

  if (isGenerating) {
    return (
      <div className="flex flex-col items-center justify-center space-y-8 min-h-[60vh] animate-in fade-in duration-500">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-600/20 border-t-indigo-500 rounded-full animate-spin"></div>
          <div className="absolute inset-0 w-20 h-20 blur-xl bg-indigo-500/10 rounded-full animate-pulse"></div>
        </div>
        <div className="text-center space-y-2">
          <p className="text-indigo-400 font-black text-xs uppercase tracking-[0.4em] animate-pulse">Synthesizing Course Data...</p>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest opacity-60">Mapping Conceptual Authorities</p>
        </div>
      </div>
    );
  }

  if (isCompleted) {
    const percentage = Math.round((score / questions.length) * 100);
    return (
      <div className="max-w-3xl mx-auto text-center space-y-12 py-10 animate-in zoom-in-95 duration-700">
        <div className="space-y-4">
          <div className="text-8xl font-black text-indigo-500 tracking-tighter leading-none drop-shadow-2xl">{percentage}%</div>
          <p className="text-slate-500 font-black uppercase tracking-[0.4em] text-[12px]">Assessment Efficiency Achieved</p>
        </div>

        <div className="bg-slate-900 border border-slate-800 p-12 rounded-[3.5rem] shadow-2xl text-left space-y-6 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/5 -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
          <h3 className="font-black text-indigo-400 text-[11px] uppercase tracking-[0.3em]">Neural Feedback</h3>
          <p className="text-lg text-slate-300 leading-relaxed font-medium break-words whitespace-pre-wrap">
            {score === questions.length 
              ? "Excellence grounded. You have fully mapped the core curriculum of this module. Your neural retention is near-perfect for this material."
              : `A productive diagnostic checkpoint. You encountered resistance in ${incorrectTopics.length} specific conceptual areas. These have been indexed for your flashcard session.`}
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-6 px-10">
          <button 
            onClick={() => onNavigateToFlashcards(incorrectTopics.join('; '))}
            className="flex-1 py-6 bg-indigo-600 text-white rounded-[2rem] font-black text-[13px] uppercase tracking-[0.2em] hover:bg-indigo-500 shadow-2xl shadow-indigo-600/30 active:scale-95 transition-all"
          >
             Ground Flashcards
          </button>
          <button onClick={startExam} className="flex-1 py-6 bg-slate-800 text-slate-300 border border-slate-700 rounded-[2rem] font-black text-[13px] uppercase tracking-[0.2em] hover:bg-slate-700 active:scale-95 transition-all">Retry Session</button>
        </div>
      </div>
    );
  }

  if (questions.length > 0) {
    const q = questions[currentIdx];
    return (
      <div className="max-w-4xl mx-auto space-y-8 py-8 animate-in slide-in-from-bottom-8 duration-700">
        <div className="flex justify-between items-end px-6">
          <div className="space-y-2">
             <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em]">Checkpoint {currentIdx + 1} / {questions.length}</span>
             <div className="w-64 h-2 bg-slate-900 rounded-full overflow-hidden border border-slate-800 shadow-inner">
                <div className="bg-indigo-500 h-full transition-all duration-700 shadow-lg shadow-indigo-500/40" style={{ width: `${((currentIdx + 1) / questions.length) * 100}%` }}></div>
             </div>
          </div>
          <div className="text-right">
             <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest block mb-1 opacity-70">Knowledge Score</span>
             <span className="text-2xl font-black text-white">{score} Matches</span>
          </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] p-12 md:p-16 space-y-12 shadow-[0_30px_100px_-15px_rgba(0,0,0,0.5)] relative overflow-hidden min-h-[400px] flex flex-col justify-center">
          <h3 className="text-2xl md:text-3xl font-black leading-tight text-white tracking-tight break-words whitespace-pre-wrap">
            {q.question}
          </h3>

          <div className="grid grid-cols-1 gap-5">
            {q.options.map((opt, i) => (
              <button 
                key={i}
                onClick={() => setSelectedAnswer(i)}
                className={`
                  w-full text-left p-7 rounded-[2rem] border transition-all duration-400 flex items-center space-x-6 relative group
                  ${selectedAnswer === i 
                    ? 'bg-indigo-600/15 border-indigo-500 text-white shadow-2xl ring-1 ring-indigo-500/30' 
                    : 'bg-slate-950/50 border-slate-800 text-slate-400 hover:border-slate-600 hover:bg-slate-900 hover:text-slate-100 shadow-md'}
                `}
              >
                <span className={`w-11 h-11 rounded-2xl flex items-center justify-center text-xs font-black shrink-0 transition-all duration-500 ${selectedAnswer === i ? 'bg-indigo-600 text-white scale-110 rotate-2 shadow-lg' : 'bg-slate-800 border border-slate-700 text-slate-500'}`}>
                  {String.fromCharCode(65 + i)}
                </span>
                <span className="text-[16px] font-bold leading-relaxed break-words flex-1 pr-4">{opt}</span>
                {selectedAnswer === i && (
                  <div className="absolute right-8 top-1/2 -translate-y-1/2 shrink-0">
                    <div className="w-3 h-3 bg-indigo-500 rounded-full animate-ping opacity-75"></div>
                  </div>
                )}
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-center pt-8">
          <button 
            disabled={selectedAnswer === null}
            onClick={handleNext}
            className={`px-20 py-6 rounded-[2rem] font-black text-[14px] uppercase tracking-[0.3em] transition-all shadow-2xl ${selectedAnswer !== null ? 'bg-indigo-600 text-white hover:bg-indigo-500 hover:scale-105 active:scale-95 shadow-indigo-600/40' : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-slate-800 opacity-40'}`}
          >
            {currentIdx === questions.length - 1 ? 'Analyze Mastery' : 'Proceed Checkpoint'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center space-y-12 min-h-[60vh] text-center max-w-2xl mx-auto py-12 animate-in fade-in duration-700">
      <div className="p-14 bg-indigo-600/10 rounded-[4rem] border border-indigo-500/20 shadow-2xl shadow-indigo-600/5 relative group">
         <div className="absolute inset-0 bg-indigo-500 blur-3xl opacity-10 group-hover:opacity-20 transition-all duration-700"></div>
         <svg className="w-20 h-20 text-indigo-500 relative transition-transform duration-700 group-hover:scale-110" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
      </div>
      <div className="space-y-5 px-6">
        <h2 className="text-5xl font-black tracking-tight text-white leading-tight break-words">Syllabus Mastery Diagnostic</h2>
        <p className="text-slate-400 text-lg font-medium leading-relaxed max-w-md mx-auto break-words">Generate a custom academic assessment grounded strictly in your personal study materials to identify conceptual weak points.</p>
      </div>
      <button 
        onClick={startExam}
        className="px-16 py-6 bg-indigo-600 text-white rounded-[2.5rem] font-black text-[14px] uppercase tracking-[0.3em] transition-all hover:bg-indigo-500 hover:scale-105 active:scale-95 shadow-2xl shadow-indigo-600/40"
      >
        Synthesize Assessment
      </button>
    </div>
  );
};

export default ExamMode;

import React, { useState, useEffect } from 'react';
import { PDFDocument, FlashCard } from '../types';
import { generateFlashcards } from '../services/geminiService';

interface FlashcardsViewProps {
  documents: PDFDocument[];
  weaknesses?: string;
}

const FlashcardsView: React.FC<FlashcardsViewProps> = ({ documents, weaknesses = "" }) => {
  const [cards, setCards] = useState<FlashCard[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (documents.length > 0) {
      loadCards();
    }
  }, [documents]);

  const loadCards = async () => {
    setIsLoading(true);
    try {
      const context = documents.map(d => d.content).join('\n');
      const generated = await generateFlashcards(context, weaknesses);
      setCards(generated);
      setCurrentIdx(0);
      setFlipped(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleNext = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev + 1) % cards.length);
    }, 150);
  };

  const handlePrev = () => {
    setFlipped(false);
    setTimeout(() => {
      setCurrentIdx((prev) => (prev - 1 + cards.length) % cards.length);
    }, 150);
  };

  if (documents.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-12 animate-in fade-in duration-700">
         <div className="p-10 bg-slate-900 rounded-[3rem] border border-slate-800 mb-8 text-slate-700 shadow-2xl">
            <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2" /></svg>
         </div>
         <h2 className="text-3xl font-black text-white tracking-tight uppercase">Active Recall Engine</h2>
         <p className="text-slate-500 mt-4 max-w-sm mx-auto text-base font-medium leading-relaxed break-words">Ground your neural hub with academic material to generate personalized recall cards.</p>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 animate-in fade-in duration-500">
        <div className="relative">
          <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
          <div className="absolute inset-0 w-20 h-20 blur-xl bg-indigo-500/10 rounded-full animate-pulse"></div>
        </div>
        <div className="text-center space-y-2">
          <p className="text-indigo-400 font-black text-xs uppercase tracking-[0.4em] animate-pulse">Encoding Active Recall Cards...</p>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest opacity-60">Syllabus Synthesis in Progress</p>
        </div>
      </div>
    );
  }

  if (cards.length === 0) return null;

  const card = cards[currentIdx];

  return (
    <div className="max-w-4xl mx-auto py-12 px-6 flex flex-col items-center space-y-12 animate-in fade-in duration-700">
      <div className="text-center space-y-3">
        <h2 className="text-4xl font-black uppercase tracking-tighter text-white">Neural Recall Hub</h2>
        <div className="inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full">
          <p className="text-indigo-400 font-black text-[10px] tracking-[0.3em] uppercase">
            {weaknesses ? 'Weakness-Targeted Session' : 'Comprehensive Module Mastery'}
          </p>
        </div>
      </div>

      <div 
        className="group relative w-full max-w-2xl h-[450px] [perspective:1000px] cursor-pointer"
        onClick={() => setFlipped(!flipped)}
      >
        <div className={`relative w-full h-full transition-all duration-700 [transform-style:preserve-3d] ${flipped ? '[transform:rotateY(180deg)]' : ''}`}>
          {/* Front Face */}
          <div className="absolute inset-0 bg-slate-900 border-2 border-slate-800 rounded-[3.5rem] p-12 flex flex-col items-center justify-center text-center shadow-[0_30px_100px_-15px_rgba(0,0,0,0.6)] [backface-visibility:hidden] overflow-y-auto chat-scroll">
            <span className="absolute top-10 text-[11px] font-black text-indigo-500 uppercase tracking-[0.4em] opacity-80">Knowledge Query</span>
            <div className="flex flex-col items-center justify-center w-full px-4 h-full">
               <p className="text-2xl md:text-3xl font-black text-slate-100 leading-tight tracking-tight break-words whitespace-pre-wrap">{card.front}</p>
            </div>
            <div className="absolute bottom-10 flex items-center space-x-3 text-[10px] font-bold text-slate-600 uppercase tracking-widest bg-slate-950/50 px-5 py-2 rounded-full border border-slate-800">
               <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M7 16l-4-4m0 0l4-4m-4 4h18" /></svg>
               <span>Tap to decode answer</span>
            </div>
          </div>

          {/* Back Face */}
          <div className="absolute inset-0 bg-indigo-600 border-2 border-indigo-400 rounded-[3.5rem] p-12 flex flex-col items-center justify-center text-center shadow-2xl [transform:rotateY(180deg)] [backface-visibility:hidden] overflow-y-auto chat-scroll">
            <span className="absolute top-10 text-[11px] font-black text-indigo-100 uppercase tracking-[0.4em] opacity-80">Grounded Logic</span>
            <div className="flex flex-col items-center justify-center w-full px-4 h-full">
               <p className="text-2xl md:text-3xl font-black text-white leading-tight tracking-tight break-words whitespace-pre-wrap">{card.back}</p>
            </div>
            <div className="absolute bottom-10 px-5 py-2 bg-black/20 rounded-full text-[10px] font-black text-white uppercase tracking-widest shadow-lg">Concept Neural Locked</div>
          </div>
        </div>
      </div>

      <div className="flex items-center space-x-16">
        <button onClick={handlePrev} className="p-7 bg-slate-900 border border-slate-800 rounded-[2rem] hover:bg-slate-800 transition-all active:scale-90 shadow-2xl group">
          <svg className="w-8 h-8 text-slate-500 group-hover:text-indigo-400 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div className="flex flex-col items-center">
          <span className="text-lg font-black text-white tracking-widest">{currentIdx + 1}</span>
          <div className="w-10 h-0.5 bg-indigo-500 rounded-full opacity-50"></div>
          <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest mt-1">of {cards.length}</span>
        </div>
        <button onClick={handleNext} className="p-7 bg-slate-900 border border-slate-800 rounded-[2rem] hover:bg-slate-800 transition-all active:scale-90 shadow-2xl group">
          <svg className="w-8 h-8 text-slate-500 group-hover:text-indigo-400 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>

      <button 
        onClick={loadCards}
        className="px-16 py-6 bg-slate-900 border border-slate-800 text-slate-400 rounded-[2rem] font-black text-[11px] uppercase tracking-[0.4em] hover:bg-slate-800 hover:text-white transition-all shadow-2xl active:scale-95"
      >
        Regenerate Neural Deck
      </button>
    </div>
  );
};

export default FlashcardsView;
